INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-dv-100', 'DV-100', 'DV-100', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "DV-100", "form_title": "Request for Domestic Violence Restraining Order", "statutory_authority": "Family Code \u00a7\u00a7 6200-6389", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "protected_person", "fields": [{"field_id": "dv100_your_name", "field_label": "Your name (person asking for protection)", "field_type": "text", "required": true, "guidance": {"en": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "es": "Ingrese su nombre legal completo. Usted es la ''persona protegida''.", "zh": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "vi": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "so": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "ti": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "am": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "ar": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "ht": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "ko": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "pt": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "ru": "Enter your full legal name. You are the ''protected person'' requesting the restraining order.", "tl": "Enter your full legal name. You are the ''protected person'' requesting the restraining order."}, "legal_reference": "", "common_errors": {}, "tips": {}}, {"field_id": "dv100_relationship", "field_label": "Relationship to restrained person", "field_type": "select", "required": true, "guidance": {"en": "Select your relationship: married/domestic partners, formerly married, dating/formerly dating, parent of same child, cohabitant/former cohabitant, closely related by blood.", "es": "Seleccione su relaci\u00f3n con la persona restringida.", "zh": "Select your relationship: married/domestic partners, formerly married, dating/formerly dating, parent of same child, cohabitant/former cohabitant, closely related by blood.", "vi": "Select your relationship: married/domestic partners, formerly married, dating/formerly dating, parent of same child, cohabitant/former cohabitant, closely related by blood.", "so": "Select your relationship.", "ti": "Select your relationship.", "am": "Select your relationship.", "ar": "Select your relationship.", "ht": "Select your relationship.", "ko": "Select your relationship.", "pt": "Select your relationship.", "ru": "Select your relationship.", "tl": "Select your relationship."}, "legal_reference": "Family Code \u00a7 6211", "common_errors": {"en": "The court must find a qualifying relationship under Family Code \u00a7 6211 to issue a DVRO.", "es": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "zh": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "vi": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "so": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "ti": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "am": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "ar": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "ht": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "ko": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "pt": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "ru": "The court must find a qualifying relationship under Family Code \u00a7 6211.", "tl": "The court must find a qualifying relationship under Family Code \u00a7 6211."}, "tips": {}}]}, {"section_id": "restrained_person", "fields": [{"field_id": "dv100_restrained_name", "field_label": "Name of person to be restrained", "field_type": "text", "required": true, "guidance": {"en": "Enter the full legal name of the person you want restrained. Include any known aliases.", "es": "Ingrese el nombre legal completo de la persona que desea restringir.", "zh": "Enter the full legal name of the person you want restrained.", "vi": "Enter the full legal name of the person you want restrained.", "so": "Enter the full legal name of the person you want restrained.", "ti": "Enter the full legal name of the person you want restrained.", "am": "Enter the full legal name of the person you want restrained.", "ar": "Enter the full legal name of the person you want restrained.", "ht": "Enter the full legal name of the person you want restrained.", "ko": "Enter the full legal name of the person you want restrained.", "pt": "Enter the full legal name of the person you want restrained.", "ru": "Enter the full legal name of the person you want restrained.", "tl": "Enter the full legal name of the person you want restrained."}, "legal_reference": "", "common_errors": {}, "tips": {}}, {"field_id": "dv100_restrained_address", "field_label": "Address of restrained person", "field_type": "text", "required": false, "guidance": {"en": "Enter the address of the person to be restrained. This is needed for service of process. If unknown, write ''Unknown''.", "es": "Ingrese la direcci\u00f3n de la persona a restringir.", "zh": "Enter the address. If unknown, write ''Unknown''.", "vi": "Enter the address. If unknown, write ''Unknown''.", "so": "Enter the address. If unknown, write ''Unknown''.", "ti": "Enter the address. If unknown, write ''Unknown''.", "am": "Enter the address. If unknown, write ''Unknown''.", "ar": "Enter the address. If unknown, write ''Unknown''.", "ht": "Enter the address. If unknown, write ''Unknown''.", "ko": "Enter the address. If unknown, write ''Unknown''.", "pt": "Enter the address. If unknown, write ''Unknown''.", "ru": "Enter the address. If unknown, write ''Unknown''.", "tl": "Enter the address. If unknown, write ''Unknown''."}, "legal_reference": "", "common_errors": {}, "tips": {}}]}, {"section_id": "abuse_description", "fields": [{"field_id": "dv100_abuse_description", "field_label": "Describe the abuse", "field_type": "textarea", "required": true, "guidance": {"en": "Describe in detail what happened. Include: dates and times, specific acts of abuse (hitting, threatening, stalking, harassing, destroying property), injuries, weapons involved, witnesses. Be specific \u2014 the judge needs facts to grant the order.", "es": "Describa en detalle lo que sucedi\u00f3. Incluya fechas, actos espec\u00edficos de abuso, lesiones.", "zh": "Describe in detail what happened. Include dates, specific acts, injuries, weapons, witnesses.", "vi": "Describe in detail what happened. Include dates, specific acts, injuries, weapons, witnesses.", "so": "Describe in detail what happened.", "ti": "Describe in detail what happened.", "am": "Describe in detail what happened.", "ar": "Describe in detail what happened.", "ht": "Describe in detail what happened.", "ko": "Describe in detail what happened.", "pt": "Describe in detail what happened.", "ru": "Describe in detail what happened.", "tl": "Describe in detail what happened."}, "legal_reference": "Family Code \u00a7\u00a7 6203, 6300, 6320", "common_errors": {"en": "Being too vague or general. The court needs specific incidents with dates and details.", "es": "Being too vague or general.", "zh": "Being too vague or general.", "vi": "Being too vague or general.", "so": "Being too vague or general.", "ti": "Being too vague or general.", "am": "Being too vague or general.", "ar": "Being too vague or general.", "ht": "Being too vague or general.", "ko": "Being too vague or general.", "pt": "Being too vague or general.", "ru": "Being too vague or general.", "tl": "Being too vague or general."}, "tips": {"en": "Start with the most recent incident, then describe the pattern. Include dates wherever possible.", "es": "Start with the most recent incident.", "zh": "Start with the most recent incident.", "vi": "Start with the most recent incident.", "so": "Start with the most recent incident.", "ti": "Start with the most recent incident.", "am": "Start with the most recent incident.", "ar": "Start with the most recent incident.", "ht": "Start with the most recent incident.", "ko": "Start with the most recent incident.", "pt": "Start with the most recent incident.", "ru": "Start with the most recent incident.", "tl": "Start with the most recent incident."}}]}, {"section_id": "orders_requested", "fields": [{"field_id": "dv100_personal_conduct", "field_label": "Personal conduct orders", "field_type": "checkbox", "required": true, "guidance": {"en": "Check all that apply: no contact, no harassing, no stalking, no threatening, no destroying property, no disturbing the peace.", "es": "Marque todo lo que aplique: sin contacto, sin acoso, sin amenazas.", "zh": "Check all that apply.", "vi": "Check all that apply.", "so": "Check all that apply.", "ti": "Check all that apply.", "am": "Check all that apply.", "ar": "Check all that apply.", "ht": "Check all that apply.", "ko": "Check all that apply.", "pt": "Check all that apply.", "ru": "Check all that apply.", "tl": "Check all that apply."}, "legal_reference": "Family Code \u00a7 6320", "common_errors": {}, "tips": {}}, {"field_id": "dv100_stay_away", "field_label": "Stay-away order distance", "field_type": "text", "required": true, "guidance": {"en": "Enter the distance (in yards) you want the restrained person to stay away from you, your home, workplace, school, children''s school. Common distances: 100 yards.", "es": "Ingrese la distancia que desea que la persona restringida se mantenga alejada.", "zh": "Enter the stay-away distance in yards.", "vi": "Enter the stay-away distance in yards.", "so": "Enter the stay-away distance.", "ti": "Enter the stay-away distance.", "am": "Enter the stay-away distance.", "ar": "Enter the stay-away distance.", "ht": "Enter the stay-away distance.", "ko": "Enter the stay-away distance.", "pt": "Enter the stay-away distance.", "ru": "Enter the stay-away distance.", "tl": "Enter the stay-away distance."}, "legal_reference": "Family Code \u00a7 6320(a)", "common_errors": {}, "tips": {}}, {"field_id": "dv100_move_out", "field_label": "Move-out order", "field_type": "checkbox", "required": false, "guidance": {"en": "If you share a residence, you can request the restrained person be ordered to move out.", "es": "Si comparten residencia, puede solicitar que la persona restringida se mude.", "zh": "If you share a residence, you can request a move-out order.", "vi": "If you share a residence, you can request a move-out order.", "so": "Request move-out if sharing residence.", "ti": "Request move-out if sharing residence.", "am": "Request move-out if sharing residence.", "ar": "Request move-out if sharing residence.", "ht": "Request move-out if sharing residence.", "ko": "Request move-out if sharing residence.", "pt": "Request move-out if sharing residence.", "ru": "Request move-out if sharing residence.", "tl": "Request move-out if sharing residence."}, "legal_reference": "Family Code \u00a7 6321", "common_errors": {}, "tips": {}}, {"field_id": "dv100_child_custody", "field_label": "Temporary child custody", "field_type": "checkbox", "required": false, "guidance": {"en": "You can request temporary custody of children as part of the DVRO. If checked, also complete FL-311.", "es": "Puede solicitar custodia temporal de los hijos como parte de la orden.", "zh": "You can request temporary custody. If checked, also complete FL-311.", "vi": "You can request temporary custody. If checked, also complete FL-311.", "so": "Request temporary custody if needed. Complete FL-311.", "ti": "Request temporary custody if needed. Complete FL-311.", "am": "Request temporary custody if needed. Complete FL-311.", "ar": "Request temporary custody if needed. Complete FL-311.", "ht": "Request temporary custody if needed. Complete FL-311.", "ko": "Request temporary custody if needed. Complete FL-311.", "pt": "Request temporary custody if needed. Complete FL-311.", "ru": "Request temporary custody if needed. Complete FL-311.", "tl": "Request temporary custody if needed. Complete FL-311."}, "legal_reference": "Family Code \u00a7\u00a7 6323, 3044", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-dv-109', 'DV-109', 'DV-109', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "DV-109", "form_title": "Notice of Court Hearing (Domestic Violence)", "statutory_authority": "Family Code \u00a7 6306; CRC Rule 5.62", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "hearing_info", "fields": [{"field_id": "dv109_hearing_date", "field_label": "Hearing date and time", "field_type": "date", "required": true, "guidance": {"en": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "es": "La fecha y hora de su audiencia de orden de restricci\u00f3n.", "zh": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "vi": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "so": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "ti": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "am": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "ar": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "ht": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "ko": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "pt": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "ru": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued.", "tl": "The date and time of your DVRO hearing, set by the court. This is when both parties appear before the judge to determine whether a permanent restraining order will be issued."}, "legal_reference": "Family Code \u00a7 6306", "common_errors": {}, "tips": {}}, {"field_id": "dv109_court_location", "field_label": "Court address and department", "field_type": "text", "required": true, "guidance": {"en": "The specific courthouse address and department number where the hearing will take place.", "es": "La direcci\u00f3n espec\u00edfica del tribunal y n\u00famero de departamento.", "zh": "The specific courthouse address and department number where the hearing will take place.", "vi": "The specific courthouse address and department number where the hearing will take place.", "so": "The specific courthouse address and department number where the hearing will take place.", "ti": "The specific courthouse address and department number where the hearing will take place.", "am": "The specific courthouse address and department number where the hearing will take place.", "ar": "The specific courthouse address and department number where the hearing will take place.", "ht": "The specific courthouse address and department number where the hearing will take place.", "ko": "The specific courthouse address and department number where the hearing will take place.", "pt": "The specific courthouse address and department number where the hearing will take place.", "ru": "The specific courthouse address and department number where the hearing will take place.", "tl": "The specific courthouse address and department number where the hearing will take place."}, "legal_reference": "", "common_errors": {}, "tips": {}}]}, {"section_id": "instructions", "fields": [{"field_id": "dv109_instructions", "field_label": "Instructions for both parties", "field_type": "text", "required": true, "guidance": {"en": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "es": "Este formulario proporciona instrucciones para ambas partes.", "zh": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "vi": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "so": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "ti": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "am": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "ar": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "ht": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "ko": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "pt": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "ru": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses.", "tl": "This form provides instructions: the protected person must attend the hearing; the restrained person may file a DV-120 response before the hearing; both parties can present evidence and witnesses."}, "legal_reference": "CRC Rule 5.62", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-dv-110', 'DV-110', 'DV-110', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "DV-110", "form_title": "Temporary Restraining Order", "statutory_authority": "Family Code \u00a7\u00a7 6300-6306", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "court_orders", "fields": [{"field_id": "dv110_orders_granted", "field_label": "Orders granted by the court", "field_type": "checkbox", "required": true, "guidance": {"en": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "es": "Este formulario es completado POR EL TRIBUNAL despu\u00e9s de revisar su solicitud DV-100.", "zh": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "vi": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "so": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "ti": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "am": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "ar": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "ht": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "ko": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "pt": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "ru": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does.", "tl": "This form is completed BY THE COURT after reviewing your DV-100 request. The judge checks which temporary orders are granted pending the hearing. You do not fill this out \u2014 the court does."}, "legal_reference": "Family Code \u00a7 6300", "common_errors": {}, "tips": {}}, {"field_id": "dv110_hearing_date", "field_label": "Hearing date", "field_type": "date", "required": true, "guidance": {"en": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "es": "El tribunal fijar\u00e1 una fecha de audiencia dentro de 21-25 d\u00edas.", "zh": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "vi": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "so": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "ti": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "am": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "ar": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "ht": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "ko": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "pt": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "ru": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date.", "tl": "The court will set a hearing date within 21-25 days. You MUST serve the restrained person with these papers before the hearing date."}, "legal_reference": "Family Code \u00a7 6306; CCP \u00a7 527(d)", "common_errors": {"en": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "es": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "zh": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "vi": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "so": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "ti": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "am": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "ar": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "ht": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "ko": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "pt": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "ru": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile.", "tl": "Failing to serve before the hearing date. If not served, the TRO expires and you must refile."}, "tips": {}}]}, {"section_id": "service_requirements", "fields": [{"field_id": "dv110_service", "field_label": "Service information", "field_type": "text", "required": true, "guidance": {"en": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "es": "La persona restringida debe recibir servicio personal de los documentos.", "zh": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "vi": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "so": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "ti": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "am": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "ar": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "ht": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "ko": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "pt": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "ru": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020).", "tl": "The restrained person must be personally served with: DV-100, DV-109, DV-110, and blank DV-120. Service must be by someone 18+ who is NOT a party to the case. Keep the proof of service (DV-020)."}, "legal_reference": "Family Code \u00a7 6306; CCP \u00a7\u00a7 414.10, 415.10", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-100', 'FL-100', 'FL-100', 'A', 'California Courts', 20, '["en","es","zh"]', '{"metadata": {"form_id": "FL-100", "title": "Petition \u2014 Marriage/Domestic Partnership", "version": "2.0.0", "created": "2026-02-24", "author": "Michael Vernen Thomas Hartmann", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "governing_statutes": ["FAM \u00a72320", "FAM \u00a72330", "CRC 5.120"], "total_fields": 28}, "fields": [{"field_id": "FL100-01", "label_en": "Attorney or Party Without Attorney (Name)", "section": "header", "type": "text", "required": true, "max_length": 60, "guidance_en": "Enter your full legal name exactly as it appears on government-issued ID. If represented by an attorney, enter the attorney''s name, State Bar number, and firm name.", "guidance_es": "Ingrese su nombre legal completo exactamente como aparece en su identificaci\u00f3n oficial. Si est\u00e1 representado por un abogado, ingrese el nombre del abogado, su n\u00famero del Colegio de Abogados y el nombre del bufete.", "guidance_zh": "\u8f93\u5165\u60a8\u653f\u5e9c\u7b7e\u53d1\u8eab\u4efd\u8bc1\u4ef6\u4e0a\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u3002\u5982\u6709\u5f8b\u5e08\u4ee3\u7406\uff0c\u8bf7\u8f93\u5165\u5f8b\u5e08\u59d3\u540d\u3001\u5dde\u5f8b\u5e08\u534f\u4f1a\u7f16\u53f7\u548c\u5f8b\u6240\u540d\u79f0\u3002", "common_errors": ["Using nicknames instead of legal name", "Omitting State Bar number when represented", "Illegible handwriting"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL100-02", "label_en": "Attorney or Party Without Attorney (Address)", "section": "header", "type": "address", "required": true, "guidance_en": "Enter a valid mailing address where you can receive court documents. A P.O. Box is acceptable. If you have a confidential address, file a request for address confidentiality (GC-120).", "guidance_es": "Ingrese una direcci\u00f3n postal v\u00e1lida donde pueda recibir documentos del tribunal. Un apartado postal es aceptable. Si tiene una direcci\u00f3n confidencial, presente una solicitud de confidencialidad de direcci\u00f3n (GC-120).", "guidance_zh": "\u8f93\u5165\u6709\u6548\u7684\u90ae\u5bc4\u5730\u5740\u4ee5\u63a5\u6536\u6cd5\u9662\u6587\u4ef6\u3002\u90ae\u653f\u4fe1\u7bb1\u53ef\u63a5\u53d7\u3002\u5982\u9700\u4fdd\u5bc6\u5730\u5740\uff0c\u8bf7\u63d0\u4ea4\u5730\u5740\u4fdd\u5bc6\u7533\u8bf7\uff08GC-120\uff09\u3002", "common_errors": ["Address does not match proof of service", "Missing city/state/zip", "Using an address where party cannot receive mail"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL100-03", "label_en": "Telephone Number", "section": "header", "type": "phone", "required": false, "guidance_en": "Enter a phone number where you can be reached. Not required but strongly recommended.", "guidance_es": "Ingrese un n\u00famero de tel\u00e9fono donde pueda ser localizado. No es obligatorio pero se recomienda.", "guidance_zh": "\u8f93\u5165\u53ef\u8054\u7cfb\u5230\u60a8\u7684\u7535\u8bdd\u53f7\u7801\u3002\u975e\u5fc5\u586b\u4f46\u5f3a\u70c8\u5efa\u8bae\u586b\u5199\u3002", "common_errors": ["Disconnected number", "Number not in service at time of filing"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL100-04", "label_en": "Email Address", "section": "header", "type": "email", "required": false, "guidance_en": "Provide an email address you check regularly. Electronic service may be authorized via this address.", "guidance_es": "Proporcione una direcci\u00f3n de correo electr\u00f3nico que revise regularmente. El servicio electr\u00f3nico puede ser autorizado a trav\u00e9s de esta direcci\u00f3n.", "guidance_zh": "\u63d0\u4f9b\u60a8\u7ecf\u5e38\u67e5\u770b\u7684\u7535\u5b50\u90ae\u4ef6\u5730\u5740\u3002\u53ef\u901a\u8fc7\u6b64\u5730\u5740\u6388\u6743\u7535\u5b50\u9001\u8fbe\u3002", "common_errors": ["Email not monitored", "Typo in email address"], "statutory_basis": "CCP \u00a71010.6"}, {"field_id": "FL100-05", "label_en": "Superior Court of California, County of", "section": "header", "type": "text", "required": true, "guidance_en": "Enter the county where you are filing. Venue is generally the county where either spouse/partner has lived for the past 3 months and in California for the past 6 months.", "guidance_es": "Ingrese el condado donde presenta la petici\u00f3n. El lugar generalmente es el condado donde cualquiera de los c\u00f3nyuges/parejas ha vivido durante los \u00faltimos 3 meses y en California durante los \u00faltimos 6 meses.", "guidance_zh": "\u8f93\u5165\u60a8\u63d0\u4ea4\u6587\u4ef6\u7684\u53bf\u3002\u7ba1\u8f96\u5730\u901a\u5e38\u662f\u914d\u5076/\u4f34\u4fa3\u4efb\u4e00\u65b9\u5728\u8fc7\u53bb3\u4e2a\u6708\u5185\u5c45\u4f4f\u7684\u53bf\uff0c\u4e14\u5728\u52a0\u5229\u798f\u5c3c\u4e9a\u5dde\u5c45\u4f4f\u6ee16\u4e2a\u6708\u3002", "common_errors": ["Filing in wrong county", "Not meeting residency requirement", "Venue confusion with UCCJEA jurisdiction"], "statutory_basis": "FAM \u00a72320"}, {"field_id": "FL100-06", "label_en": "Street Address of Court", "section": "header", "type": "address", "required": true, "guidance_en": "Enter the street address of the courthouse where you are filing. This must match the correct branch for the county listed above.", "guidance_es": "Ingrese la direcci\u00f3n del tribunal donde presenta la petici\u00f3n. Debe coincidir con la sucursal correcta del condado indicado arriba.", "guidance_zh": "\u8f93\u5165\u60a8\u63d0\u4ea4\u6587\u4ef6\u7684\u6cd5\u9662\u7684\u8857\u9053\u5730\u5740\u3002\u5fc5\u987b\u4e0e\u4e0a\u8ff0\u53bf\u7684\u6b63\u786e\u5206\u9662\u4e00\u81f4\u3002", "common_errors": ["Wrong branch courthouse address", "Using mailing address instead of street address"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL100-07", "label_en": "Petitioner (Name)", "section": "parties", "type": "text", "required": true, "guidance_en": "Enter the full legal name of the person filing the petition. This is the person initiating the dissolution, legal separation, or annulment.", "guidance_es": "Ingrese el nombre legal completo de la persona que presenta la petici\u00f3n. Esta es la persona que inicia la disoluci\u00f3n, separaci\u00f3n legal o anulaci\u00f3n.", "guidance_zh": "\u8f93\u5165\u63d0\u4ea4\u8bf7\u613f\u4e66\u7684\u4eba\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u3002\u6b64\u4eba\u4e3a\u53d1\u8d77\u89e3\u9664\u5a5a\u59fb\u3001\u5408\u6cd5\u5206\u5c45\u6216\u64a4\u9500\u5a5a\u59fb\u7684\u4e00\u65b9\u3002", "common_errors": ["Name mismatch with marriage certificate", "Using maiden vs married name inconsistently"], "statutory_basis": "FAM \u00a72330"}, {"field_id": "FL100-08", "label_en": "Respondent (Name)", "section": "parties", "type": "text", "required": true, "guidance_en": "Enter the full legal name of the other spouse or domestic partner. Must match the name on the marriage certificate or domestic partnership registration.", "guidance_es": "Ingrese el nombre legal completo del otro c\u00f3nyuge o pareja dom\u00e9stica. Debe coincidir con el nombre en el certificado de matrimonio o registro de uni\u00f3n dom\u00e9stica.", "guidance_zh": "\u8f93\u5165\u53e6\u4e00\u65b9\u914d\u5076\u6216\u5bb6\u5ead\u4f34\u4fa3\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u3002\u5fc5\u987b\u4e0e\u7ed3\u5a5a\u8bc1\u4e66\u6216\u5bb6\u5ead\u4f34\u4fa3\u767b\u8bb0\u4e0a\u7684\u59d3\u540d\u4e00\u81f4\u3002", "common_errors": ["Misspelling respondent''s legal name", "Using former name when legal name has changed"], "statutory_basis": "FAM \u00a72330"}, {"field_id": "FL100-09", "label_en": "Case Number", "section": "header", "type": "text", "required": false, "guidance_en": "Leave blank if this is a new filing. The clerk will assign a case number. If you already have a case number from a prior filing, enter it here.", "guidance_es": "Deje en blanco si es una presentaci\u00f3n nueva. El secretario asignar\u00e1 un n\u00famero de caso. Si ya tiene un n\u00famero de caso de una presentaci\u00f3n anterior, ingr\u00e9selo aqu\u00ed.", "guidance_zh": "\u5982\u679c\u662f\u65b0\u7acb\u6848\uff0c\u8bf7\u7559\u7a7a\u3002\u4e66\u8bb0\u5458\u5c06\u5206\u914d\u6848\u4ef6\u7f16\u53f7\u3002\u5982\u5df2\u6709\u5148\u524d\u7acb\u6848\u7684\u6848\u4ef6\u7f16\u53f7\uff0c\u8bf7\u5728\u6b64\u586b\u5199\u3002", "common_errors": ["Entering wrong case number from different proceeding", "Failing to use existing case number"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL100-10", "label_en": "Item 1 \u2014 Legal Relationship", "section": "body", "type": "checkbox_group", "required": true, "options": ["Dissolution (Divorce) of Marriage", "Legal Separation of Marriage", "Nullity (Annulment) of Marriage", "Dissolution of Domestic Partnership", "Legal Separation of Domestic Partnership", "Nullity of Domestic Partnership"], "guidance_en": "Check the box that describes what you are asking the court to do. Dissolution ends the marriage. Legal separation does not end the marriage but divides assets and establishes support. Nullity declares the marriage was never valid.", "guidance_es": "Marque la casilla que describe lo que le pide al tribunal. La disoluci\u00f3n termina el matrimonio. La separaci\u00f3n legal no termina el matrimonio pero divide bienes y establece manutenci\u00f3n. La nulidad declara que el matrimonio nunca fue v\u00e1lido.", "guidance_zh": "\u52fe\u9009\u63cf\u8ff0\u60a8\u8981\u6c42\u6cd5\u9662\u6267\u884c\u4e8b\u9879\u7684\u9009\u9879\u3002\u89e3\u9664\u5a5a\u59fb\u5373\u7ec8\u6b62\u5a5a\u59fb\u5173\u7cfb\u3002\u5408\u6cd5\u5206\u5c45\u4e0d\u7ec8\u6b62\u5a5a\u59fb\u4f46\u5206\u5272\u8d22\u4ea7\u5e76\u786e\u5b9a\u8d61\u517b\u8d39\u3002\u64a4\u9500\u5a5a\u59fb\u58f0\u660e\u5a5a\u59fb\u4ece\u672a\u6709\u6548\u6210\u7acb\u3002", "common_errors": ["Selecting wrong type \u2014 dissolution vs legal separation", "Not understanding annulment grounds required under FAM \u00a72210"], "statutory_basis": "FAM \u00a72310, FAM \u00a72210"}, {"field_id": "FL100-11", "label_en": "Item 2 \u2014 Residency Requirement", "section": "body", "type": "checkbox_group", "required": true, "options": ["Petitioner has been a resident for at least 6 months in CA and 3 months in this county", "Respondent has been a resident for at least 6 months in CA and 3 months in this county", "Neither party meets residency \u2014 filing for legal separation only"], "guidance_en": "At least one party must have lived in California for 6 months and in the filing county for 3 months immediately before filing. If neither meets this, you can only file for legal separation until the requirement is met.", "guidance_es": "Al menos una parte debe haber vivido en California por 6 meses y en el condado de presentaci\u00f3n por 3 meses inmediatamente antes de presentar. Si ninguna cumple, solo puede presentar separaci\u00f3n legal hasta cumplir el requisito.", "guidance_zh": "\u81f3\u5c11\u4e00\u65b9\u5fc5\u987b\u5728\u63d0\u4ea4\u524d\u5728\u52a0\u5229\u798f\u5c3c\u4e9a\u5dde\u8fde\u7eed\u5c45\u4f4f6\u4e2a\u6708\uff0c\u4e14\u5728\u7acb\u6848\u53bf\u8fde\u7eed\u5c45\u4f4f3\u4e2a\u6708\u3002\u5982\u53cc\u65b9\u5747\u4e0d\u6ee1\u8db3\uff0c\u53ea\u80fd\u5148\u7533\u8bf7\u5408\u6cd5\u5206\u5c45\uff0c\u5f85\u6ee1\u8db3\u6761\u4ef6\u540e\u518d\u884c\u8f6c\u6362\u3002", "common_errors": ["Not meeting residency at time of filing", "Checking box for wrong party", "Confusing state vs county residency"], "statutory_basis": "FAM \u00a72320"}, {"field_id": "FL100-12", "label_en": "Item 3 \u2014 Statistical Facts", "section": "body", "type": "compound", "required": true, "subfields": ["Date of marriage/partnership", "Date of separation", "Time from date of marriage to separation"], "guidance_en": "Enter the date of your marriage or registration of domestic partnership, the date of separation, and calculate the time between. The date of separation is critical \u2014 it affects community property division and may affect spousal support duration.", "guidance_es": "Ingrese la fecha de su matrimonio o registro de uni\u00f3n dom\u00e9stica, la fecha de separaci\u00f3n y calcule el tiempo entre ambas. La fecha de separaci\u00f3n es cr\u00edtica \u2014 afecta la divisi\u00f3n de bienes comunitarios y puede afectar la duraci\u00f3n de la manutenci\u00f3n conyugal.", "guidance_zh": "\u8f93\u5165\u7ed3\u5a5a\u6216\u767b\u8bb0\u5bb6\u5ead\u4f34\u4fa3\u5173\u7cfb\u7684\u65e5\u671f\u3001\u5206\u5c45\u65e5\u671f\uff0c\u5e76\u8ba1\u7b97\u4e24\u4e2a\u65e5\u671f\u4e4b\u95f4\u7684\u65f6\u95f4\u3002\u5206\u5c45\u65e5\u671f\u81f3\u5173\u91cd\u8981\u2014\u2014\u5f71\u54cd\u5171\u540c\u8d22\u4ea7\u5206\u5272\uff0c\u53ef\u80fd\u5f71\u54cd\u914d\u5076\u8d61\u517b\u8d39\u671f\u9650\u3002", "common_errors": ["Incorrect date of separation \u2014 must reflect actual intent and actions per FAM \u00a770", "Math error in duration", "Using engagement date instead of marriage date"], "statutory_basis": "FAM \u00a770, FAM \u00a72550"}, {"field_id": "FL100-13", "label_en": "Item 4 \u2014 Minor Children", "section": "body", "type": "checkbox_group", "required": true, "options": ["There are no minor children", "The minor children are (list names and birthdates)", "If there are minor children of this relationship, a completed Declaration Under UCCJEA (FL-105) must be attached", "Continued on Attachment 4"], "guidance_en": "List ALL minor children (under 18) born to or adopted by both parties during the marriage. Include full names and dates of birth. A UCCJEA declaration (FL-105) MUST be filed with this petition if there are minor children.", "guidance_es": "Enumere TODOS los hijos menores (menores de 18 a\u00f1os) nacidos o adoptados por ambas partes durante el matrimonio. Incluya nombres completos y fechas de nacimiento. Se DEBE presentar una declaraci\u00f3n UCCJEA (FL-105) con esta petici\u00f3n si hay hijos menores.", "guidance_zh": "\u5217\u51fa\u5a5a\u59fb\u671f\u95f4\u53cc\u65b9\u6240\u751f\u6216\u6536\u517b\u7684\u6240\u6709\u672a\u6210\u5e74\u5b50\u5973\uff0818\u5c81\u4ee5\u4e0b\uff09\u3002\u5305\u62ec\u5168\u540d\u548c\u51fa\u751f\u65e5\u671f\u3002\u5982\u6709\u672a\u6210\u5e74\u5b50\u5973\uff0c\u5fc5\u987b\u968f\u672c\u8bf7\u613f\u4e66\u63d0\u4ea4UCCJEA\u58f0\u660e\uff08FL-105\uff09\u3002", "common_errors": ["Omitting children from prior relationships who may be covered", "Not attaching FL-105", "Wrong birthdates", "Not listing all children"], "statutory_basis": "FAM \u00a73400, FAM \u00a73402"}, {"field_id": "FL100-14", "label_en": "Item 5 \u2014 Spousal/Partner Support", "section": "body", "type": "checkbox_group", "required": true, "options": ["Spousal/partner support payable to Petitioner", "Spousal/partner support payable to Respondent", "Terminate the court''s ability to award support to Petitioner", "Terminate the court''s ability to award support to Respondent", "Reserve jurisdiction over support"], "guidance_en": "Indicate whether you are requesting spousal/partner support, asking the court to order the other party to pay support, or requesting that the ability to award support be terminated. Termination is permanent and cannot be undone. Reserving jurisdiction preserves the right to request support later.", "guidance_es": "Indique si solicita manutenci\u00f3n conyugal/de pareja, pide al tribunal que ordene a la otra parte pagar manutenci\u00f3n, o solicita que se termine la capacidad de otorgar manutenci\u00f3n. La terminaci\u00f3n es permanente e irreversible. Reservar jurisdicci\u00f3n preserva el derecho a solicitar manutenci\u00f3n m\u00e1s adelante.", "guidance_zh": "\u8bf4\u660e\u60a8\u662f\u5426\u8981\u6c42\u914d\u5076/\u4f34\u4fa3\u8d61\u517b\u8d39\u3001\u8981\u6c42\u6cd5\u9662\u547d\u4ee4\u5bf9\u65b9\u652f\u4ed8\u8d61\u517b\u8d39\uff0c\u6216\u8981\u6c42\u7ec8\u6b62\u6cd5\u9662\u6388\u4e88\u8d61\u517b\u8d39\u7684\u6743\u529b\u3002\u7ec8\u6b62\u662f\u6c38\u4e45\u6027\u7684\uff0c\u4e0d\u53ef\u64a4\u9500\u3002\u4fdd\u7559\u7ba1\u8f96\u6743\u5219\u4fdd\u7559\u65e5\u540e\u8bf7\u6c42\u8d61\u517b\u8d39\u7684\u6743\u5229\u3002", "common_errors": ["Accidentally terminating support rights permanently", "Not understanding difference between terminate and reserve", "Checking conflicting boxes"], "statutory_basis": "FAM \u00a74330, FAM \u00a74336"}, {"field_id": "FL100-15", "label_en": "Item 6 \u2014 Separate Property", "section": "body", "type": "checkbox", "required": false, "guidance_en": "Check this box if you want the court to confirm assets and debts as separate property. Separate property is anything acquired before marriage, after separation, or by gift/inheritance during marriage.", "guidance_es": "Marque esta casilla si desea que el tribunal confirme bienes y deudas como propiedad separada.", "guidance_zh": "\u5982\u679c\u60a8\u5e0c\u671b\u6cd5\u9662\u786e\u8ba4\u8d22\u4ea7\u548c\u503a\u52a1\u4e3a\u4e2a\u4eba\u8d22\u4ea7\uff0c\u8bf7\u52fe\u9009\u6b64\u9009\u9879\u3002", "common_errors": ["Not understanding what qualifies as separate vs community property"], "statutory_basis": "FAM \u00a7770, FAM \u00a72550"}, {"field_id": "FL100-16", "label_en": "Item 7 \u2014 Community/Quasi-Community Property", "section": "body", "type": "checkbox_group", "required": false, "options": ["Determine property rights", "Award community assets to parties", "One-half to each party"], "guidance_en": "Community property includes all assets and debts acquired during the marriage. California is a community property state \u2014 the default is equal division (50/50).", "guidance_es": "La propiedad comunitaria incluye todos los bienes y deudas adquiridos durante el matrimonio. California es un estado de propiedad comunitaria \u2014 la divisi\u00f3n predeterminada es igualitaria (50/50).", "guidance_zh": "\u5171\u540c\u8d22\u4ea7\u5305\u62ec\u5a5a\u59fb\u671f\u95f4\u83b7\u5f97\u7684\u6240\u6709\u8d44\u4ea7\u548c\u503a\u52a1\u3002\u52a0\u5229\u798f\u5c3c\u4e9a\u662f\u5171\u540c\u8d22\u4ea7\u5dde\u2014\u2014\u9ed8\u8ba4\u4e3a\u5e73\u5747\u5206\u914d\uff0850/50\uff09\u3002", "common_errors": ["Not disclosing all community assets", "Confusing community and separate property"], "statutory_basis": "FAM \u00a72550, FAM \u00a72551"}, {"field_id": "FL100-17", "label_en": "Item 8 \u2014 Other Requests", "section": "body", "type": "checkbox_group", "required": false, "options": ["Attorney fees and costs", "Petitioner''s former name restored to", "Other (specify)"], "guidance_en": "Attorney fees may be awarded under FAM \u00a72030 based on disparity in income/access to funds. Name restoration is automatic upon request in a dissolution. Use ''Other'' for any additional requests not covered above.", "guidance_es": "Los honorarios de abogado pueden ser otorgados bajo FAM \u00a72030 bas\u00e1ndose en la disparidad de ingresos/acceso a fondos. La restauraci\u00f3n del nombre es autom\u00e1tica al solicitarla en una disoluci\u00f3n.", "guidance_zh": "\u5f8b\u5e08\u8d39\u53ef\u6839\u636eFAM \u00a72030\u57fa\u4e8e\u6536\u5165/\u8d44\u91d1\u83b7\u53d6\u5dee\u5f02\u800c\u5224\u5b9a\u3002\u5728\u79bb\u5a5a\u7a0b\u5e8f\u4e2d\uff0c\u6062\u590d\u539f\u59d3\u540d\u7684\u8bf7\u6c42\u81ea\u52a8\u83b7\u6279\u3002", "common_errors": ["Not requesting name restoration at this stage", "Not specifying ''Other'' clearly"], "statutory_basis": "FAM \u00a72030, FAM \u00a72080"}, {"field_id": "FL100-18", "label_en": "Item 9 \u2014 Child Custody", "section": "body", "type": "checkbox_group", "required": false, "options": ["Legal custody to Petitioner", "Legal custody to Respondent", "Joint legal custody", "Physical custody to Petitioner", "Physical custody to Respondent", "Joint physical custody", "Child visitation to Petitioner", "Child visitation to Respondent", "As stated in attached FL-311"], "guidance_en": "Legal custody = decision-making authority (education, health, welfare). Physical custody = where the child primarily resides. Joint means shared. Attach FL-311 for detailed custody requests.", "guidance_es": "Custodia legal = autoridad de decisi\u00f3n (educaci\u00f3n, salud, bienestar). Custodia f\u00edsica = donde reside principalmente el ni\u00f1o. Conjunta significa compartida. Adjunte FL-311 para solicitudes detalladas.", "guidance_zh": "\u6cd5\u5b9a\u76d1\u62a4\u6743=\u51b3\u7b56\u6743\uff08\u6559\u80b2\u3001\u5065\u5eb7\u3001\u798f\u5229\uff09\u3002\u5b9e\u9645\u76d1\u62a4\u6743=\u5b50\u5973\u4e3b\u8981\u5c45\u4f4f\u5730\u3002\u5171\u540c\u610f\u5473\u7740\u5171\u4eab\u3002\u5982\u9700\u8be6\u7ec6\u7684\u76d1\u62a4\u6743\u8bf7\u6c42\uff0c\u8bf7\u9644\u4e0aFL-311\u3002", "common_errors": ["Confusing legal and physical custody", "Not attaching FL-311 for detailed orders", "Requesting sole custody without factual basis"], "statutory_basis": "FAM \u00a73003, FAM \u00a73006, FAM \u00a73020"}, {"field_id": "FL100-19", "label_en": "Item 10 \u2014 Child Support", "section": "body", "type": "checkbox", "required": false, "guidance_en": "Check if you are requesting the court to order child support. California uses a guideline formula based on income and timeshare percentage (FAM \u00a74055).", "guidance_es": "Marque si solicita al tribunal que ordene manutenci\u00f3n de menores. California usa una f\u00f3rmula gu\u00eda basada en ingresos y porcentaje de tiempo compartido (FAM \u00a74055).", "guidance_zh": "\u5982\u679c\u60a8\u8981\u6c42\u6cd5\u9662\u547d\u4ee4\u652f\u4ed8\u5b50\u5973\u629a\u517b\u8d39\uff0c\u8bf7\u52fe\u9009\u3002\u52a0\u5229\u798f\u5c3c\u4e9a\u4f7f\u7528\u57fa\u4e8e\u6536\u5165\u548c\u65f6\u95f4\u5206\u914d\u767e\u5206\u6bd4\u7684\u6307\u5bfc\u516c\u5f0f\uff08FAM \u00a74055\uff09\u3002", "common_errors": ["Not requesting support when entitled", "Not understanding guideline calculation"], "statutory_basis": "FAM \u00a74050, FAM \u00a74055"}, {"field_id": "FL100-20", "label_en": "Declaration Under Penalty of Perjury", "section": "signature", "type": "signature_block", "required": true, "guidance_en": "Sign and date the form under penalty of perjury. Your signature certifies that all information in the petition is true and correct to the best of your knowledge. False statements may result in criminal prosecution.", "guidance_es": "Firme y feche el formulario bajo pena de perjurio. Su firma certifica que toda la informaci\u00f3n en la petici\u00f3n es verdadera y correcta seg\u00fan su mejor conocimiento. Las declaraciones falsas pueden resultar en procesamiento penal.", "guidance_zh": "\u5728\u4f2a\u8bc1\u5904\u7f5a\u6761\u6b3e\u4e0b\u7b7e\u540d\u5e76\u6ce8\u660e\u65e5\u671f\u3002\u60a8\u7684\u7b7e\u540d\u8bc1\u660e\u8bf7\u613f\u4e66\u4e2d\u7684\u6240\u6709\u4fe1\u606f\u636e\u60a8\u6240\u77e5\u662f\u771f\u5b9e\u548c\u6b63\u786e\u7684\u3002\u865a\u5047\u9648\u8ff0\u53ef\u80fd\u5bfc\u81f4\u5211\u4e8b\u8d77\u8bc9\u3002", "common_errors": ["Forgetting to sign", "Signing wrong date", "Not including city and state in verification"], "statutory_basis": "CCP \u00a72015.5"}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-110', 'FL-110', 'FL-110', 'A', 'California Courts', 10, '["en","es","zh"]', '{"metadata": {"form_id": "FL-110", "title": "Summons (Family Law)", "version": "2.0.0", "created": "2026-02-24", "author": "Michael Vernen Thomas Hartmann", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "governing_statutes": ["CCP \u00a7412.20", "FAM \u00a72040", "CRC 5.50"], "total_fields": 12}, "fields": [{"field_id": "FL110-01", "label_en": "Petitioner (Name)", "section": "header", "type": "text", "required": true, "guidance_en": "Enter the full legal name of the Petitioner exactly as it appears on the FL-100 petition.", "guidance_es": "Ingrese el nombre legal completo del Peticionario exactamente como aparece en la petici\u00f3n FL-100.", "guidance_zh": "\u8f93\u5165\u8bf7\u613f\u4eba\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\uff0c\u4e0eFL-100\u8bf7\u613f\u4e66\u4e0a\u7684\u59d3\u540d\u5b8c\u5168\u4e00\u81f4\u3002", "common_errors": ["Name mismatch with FL-100", "Using nickname or shortened name"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL110-02", "label_en": "Respondent (Name)", "section": "header", "type": "text", "required": true, "guidance_en": "Enter the full legal name of the Respondent exactly as it appears on the FL-100 petition.", "guidance_es": "Ingrese el nombre legal completo del Demandado exactamente como aparece en la petici\u00f3n FL-100.", "guidance_zh": "\u8f93\u5165\u88ab\u544a\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\uff0c\u4e0eFL-100\u8bf7\u613f\u4e66\u4e0a\u7684\u59d3\u540d\u5b8c\u5168\u4e00\u81f4\u3002", "common_errors": ["Name mismatch with FL-100"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL110-03", "label_en": "Notice to Respondent \u2014 Standard Restraining Orders", "section": "body", "type": "informational", "required": false, "guidance_en": "This section is pre-printed. It contains the automatic temporary restraining orders (ATROs) that go into effect upon service. Both parties are restrained from: removing minor children from the state, transferring/disposing of property, changing insurance beneficiaries, and incurring new debt. READ CAREFULLY \u2014 violations are contempt of court.", "guidance_es": "Esta secci\u00f3n est\u00e1 preimpresa. Contiene las \u00f3rdenes de restricci\u00f3n temporales autom\u00e1ticas (ATROs) que entran en vigor al momento de la notificaci\u00f3n. Ambas partes tienen prohibido: sacar a los hijos menores del estado, transferir/disponer de bienes, cambiar beneficiarios de seguros e incurrir en nueva deuda. LEA CUIDADOSAMENTE \u2014 las violaciones constituyen desacato al tribunal.", "guidance_zh": "\u672c\u8282\u4e3a\u9884\u5370\u5185\u5bb9\u3002\u5305\u542b\u9001\u8fbe\u540e\u81ea\u52a8\u751f\u6548\u7684\u4e34\u65f6\u9650\u5236\u4ee4\uff08ATROs\uff09\u3002\u53cc\u65b9\u5747\u88ab\u9650\u5236\uff1a\u4e0d\u5f97\u5c06\u672a\u6210\u5e74\u5b50\u5973\u5e26\u79bb\u5dde\u5916\u3001\u4e0d\u5f97\u8f6c\u8ba9/\u5904\u5206\u8d22\u4ea7\u3001\u4e0d\u5f97\u66f4\u6539\u4fdd\u9669\u53d7\u76ca\u4eba\u3001\u4e0d\u5f97\u4ea7\u751f\u65b0\u503a\u52a1\u3002\u8bf7\u4ed4\u7ec6\u9605\u8bfb\u2014\u2014\u8fdd\u53cd\u6784\u6210\u85d0\u89c6\u6cd5\u5ead\u3002", "common_errors": ["Respondent not reading ATROs", "Petitioner not understanding ATROs apply to BOTH parties", "Violating ATROs by transferring assets before service"], "statutory_basis": "FAM \u00a72040"}, {"field_id": "FL110-04", "label_en": "Notice \u2014 Access to Affordable Health Insurance", "section": "body", "type": "informational", "required": false, "guidance_en": "Pre-printed notice informing parties about health insurance options through Covered California during dissolution proceedings.", "guidance_es": "Aviso preimpreso informando a las partes sobre opciones de seguro m\u00e9dico a trav\u00e9s de Covered California durante los procedimientos de disoluci\u00f3n.", "guidance_zh": "\u9884\u5370\u901a\u77e5\uff0c\u544a\u77e5\u5f53\u4e8b\u4eba\u5728\u79bb\u5a5a\u7a0b\u5e8f\u671f\u95f4\u53ef\u901a\u8fc7Covered California\u83b7\u53d6\u5065\u5eb7\u4fdd\u9669\u9009\u9879\u3002", "common_errors": ["Ignoring health insurance planning during dissolution"], "statutory_basis": "FAM \u00a72024"}, {"field_id": "FL110-05", "label_en": "Case Number", "section": "header", "type": "text", "required": true, "guidance_en": "The case number assigned by the clerk when the FL-100 was filed. Must match the case number on all documents in this proceeding.", "guidance_es": "El n\u00famero de caso asignado por el secretario cuando se present\u00f3 el FL-100. Debe coincidir con el n\u00famero de caso en todos los documentos de este procedimiento.", "guidance_zh": "\u63d0\u4ea4FL-100\u65f6\u7531\u4e66\u8bb0\u5458\u5206\u914d\u7684\u6848\u4ef6\u7f16\u53f7\u3002\u5fc5\u987b\u4e0e\u672c\u6848\u6240\u6709\u6587\u4ef6\u4e0a\u7684\u6848\u4ef6\u7f16\u53f7\u4e00\u81f4\u3002", "common_errors": ["Wrong case number", "Case number not yet assigned at time of preparation"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL110-06", "label_en": "30-Day Response Notice", "section": "body", "type": "informational", "required": false, "guidance_en": "Pre-printed notice stating respondent has 30 calendar days after service to file a response (FL-120). Failure to respond may result in default judgment. The 30-day period begins the day AFTER personal service or acknowledgment of receipt.", "guidance_es": "Aviso preimpreso indicando que el demandado tiene 30 d\u00edas calendario despu\u00e9s de la notificaci\u00f3n para presentar una respuesta (FL-120). No responder puede resultar en un fallo en rebeld\u00eda.", "guidance_zh": "\u9884\u5370\u901a\u77e5\uff0c\u8bf4\u660e\u88ab\u544a\u5728\u9001\u8fbe\u540e30\u4e2a\u65e5\u5386\u65e5\u5185\u987b\u63d0\u4ea4\u7b54\u8fa9\u4e66\uff08FL-120\uff09\u3002\u672a\u80fd\u56de\u5e94\u53ef\u80fd\u5bfc\u81f4\u7f3a\u5e2d\u5224\u51b3\u300230\u5929\u671f\u9650\u4ece\u4eb2\u81ea\u9001\u8fbe\u6216\u786e\u8ba4\u6536\u5230\u7684\u6b21\u65e5\u8d77\u7b97\u3002", "common_errors": ["Miscounting the 30-day deadline", "Not understanding service date vs filing date", "Confusing calendar days with court days"], "statutory_basis": "CCP \u00a7412.20, CCP \u00a7415.20"}, {"field_id": "FL110-07", "label_en": "Fee Waiver Notice", "section": "body", "type": "informational", "required": false, "guidance_en": "Pre-printed notice informing respondent that fee waiver forms (FW-001 and FW-003) are available if they cannot afford filing fees.", "guidance_es": "Aviso preimpreso informando al demandado que los formularios de exenci\u00f3n de cuotas (FW-001 y FW-003) est\u00e1n disponibles si no puede pagar las cuotas de presentaci\u00f3n.", "guidance_zh": "\u9884\u5370\u901a\u77e5\uff0c\u544a\u77e5\u88ab\u544a\u5982\u65e0\u529b\u652f\u4ed8\u7acb\u6848\u8d39\u7528\uff0c\u53ef\u4f7f\u7528\u8d39\u7528\u514d\u9664\u8868\u683c\uff08FW-001\u548cFW-003\uff09\u3002", "common_errors": ["Respondent not seeking fee waiver when eligible"], "statutory_basis": "GOV \u00a768631"}, {"field_id": "FL110-08", "label_en": "Clerk''s Certificate of Service", "section": "footer", "type": "signature_block", "required": true, "guidance_en": "This section is completed by the court clerk. The clerk certifies that the summons was issued. Do NOT fill in this section yourself.", "guidance_es": "Esta secci\u00f3n la completa el secretario del tribunal. El secretario certifica que se emiti\u00f3 la citaci\u00f3n. NO complete esta secci\u00f3n usted mismo.", "guidance_zh": "\u672c\u8282\u7531\u6cd5\u9662\u4e66\u8bb0\u5458\u586b\u5199\u3002\u4e66\u8bb0\u5458\u8bc1\u660e\u4f20\u7968\u5df2\u7b7e\u53d1\u3002\u8bf7\u52ff\u81ea\u884c\u586b\u5199\u6b64\u90e8\u5206\u3002", "common_errors": ["Party filling in clerk section", "Summons not properly issued before service attempt"], "statutory_basis": "CCP \u00a7412.20"}, {"field_id": "FL110-09", "label_en": "Date Summons Issued", "section": "footer", "type": "date", "required": true, "guidance_en": "Date the clerk issues the summons. The summons is valid for 3 years from this date (CCP \u00a7583.210). Service must be completed within this period.", "guidance_es": "Fecha en que el secretario emite la citaci\u00f3n. La citaci\u00f3n es v\u00e1lida por 3 a\u00f1os a partir de esta fecha (CCP \u00a7583.210).", "guidance_zh": "\u4e66\u8bb0\u5458\u7b7e\u53d1\u4f20\u7968\u7684\u65e5\u671f\u3002\u4f20\u7968\u81ea\u6b64\u65e5\u671f\u8d773\u5e74\u5185\u6709\u6548\uff08CCP \u00a7583.210\uff09\u3002\u5fc5\u987b\u5728\u6b64\u671f\u9650\u5185\u5b8c\u6210\u9001\u8fbe\u3002", "common_errors": ["Attempting service after summons expires", "Not requesting reissuance when needed"], "statutory_basis": "CCP \u00a7583.210"}, {"field_id": "FL110-10", "label_en": "Clerk''s Signature", "section": "footer", "type": "signature", "required": true, "guidance_en": "Clerk signs or stamps the summons. An unsigned summons is invalid for service.", "guidance_es": "El secretario firma o sella la citaci\u00f3n. Una citaci\u00f3n sin firma es inv\u00e1lida para la notificaci\u00f3n.", "guidance_zh": "\u4e66\u8bb0\u5458\u7b7e\u540d\u6216\u76d6\u7ae0\u3002\u672a\u7b7e\u540d\u7684\u4f20\u7968\u4e0d\u80fd\u7528\u4e8e\u9001\u8fbe\u3002", "common_errors": ["Serving an unsigned summons", "Missing clerk seal"], "statutory_basis": "CCP \u00a7412.20"}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-120', 'FL-120', 'FL-120', 'A', 'California Courts', 18, '["en","es","zh"]', '{"metadata": {"form_id": "FL-120", "title": "Response \u2014 Marriage/Domestic Partnership", "version": "2.0.0", "created": "2026-02-24", "author": "Michael Vernen Thomas Hartmann", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "governing_statutes": ["FAM \u00a72020", "CCP \u00a7412.20", "CRC 5.120"], "total_fields": 22, "notes": "Mirror structure of FL-100 from respondent perspective. Must be filed within 30 days of service."}, "fields": [{"field_id": "FL120-01", "label_en": "Attorney or Party Without Attorney (Name)", "section": "header", "type": "text", "required": true, "guidance_en": "Enter the Respondent''s full legal name or attorney''s name with State Bar number. This is the person filing the response.", "guidance_es": "Ingrese el nombre legal completo del Demandado o el nombre del abogado con n\u00famero del Colegio de Abogados.", "guidance_zh": "\u8f93\u5165\u88ab\u544a\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u6216\u5f8b\u5e08\u59d3\u540d\u53ca\u5dde\u5f8b\u5e08\u534f\u4f1a\u7f16\u53f7\u3002\u6b64\u4e3a\u63d0\u4ea4\u7b54\u8fa9\u4e66\u7684\u4e00\u65b9\u3002", "common_errors": ["Name mismatch with FL-100/FL-110", "Omitting State Bar number"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL120-02", "label_en": "Attorney or Party Without Attorney (Address)", "section": "header", "type": "address", "required": true, "guidance_en": "Enter a valid mailing address for the responding party. Confidential address requests use GC-120.", "guidance_es": "Ingrese una direcci\u00f3n postal v\u00e1lida para la parte que responde. Las solicitudes de direcci\u00f3n confidencial usan GC-120.", "guidance_zh": "\u8f93\u5165\u7b54\u8fa9\u65b9\u7684\u6709\u6548\u90ae\u5bc4\u5730\u5740\u3002\u4fdd\u5bc6\u5730\u5740\u8bf7\u6c42\u4f7f\u7528GC-120\u3002", "common_errors": ["Using an address where party no longer resides", "Not filing GC-120 when address confidentiality needed"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL120-03", "label_en": "Telephone / Email", "section": "header", "type": "contact", "required": false, "guidance_en": "Phone and email are optional but recommended. Email is required for electronic service consent.", "guidance_es": "El tel\u00e9fono y correo electr\u00f3nico son opcionales pero recomendados. Se requiere correo electr\u00f3nico para consentir servicio electr\u00f3nico.", "guidance_zh": "\u7535\u8bdd\u548c\u7535\u5b50\u90ae\u4ef6\u4e3a\u53ef\u9009\u4f46\u5efa\u8bae\u586b\u5199\u3002\u540c\u610f\u7535\u5b50\u9001\u8fbe\u9700\u63d0\u4f9b\u7535\u5b50\u90ae\u4ef6\u3002", "common_errors": ["Providing inactive contact information"], "statutory_basis": "CCP \u00a71010.6"}, {"field_id": "FL120-04", "label_en": "Superior Court / County / Court Address", "section": "header", "type": "text", "required": true, "guidance_en": "Must match the court where the Petition (FL-100) was filed. The response MUST be filed in the same court and county as the original petition.", "guidance_es": "Debe coincidir con el tribunal donde se present\u00f3 la Petici\u00f3n (FL-100). La respuesta DEBE presentarse en el mismo tribunal y condado que la petici\u00f3n original.", "guidance_zh": "\u5fc5\u987b\u4e0e\u63d0\u4ea4\u8bf7\u613f\u4e66\uff08FL-100\uff09\u7684\u6cd5\u9662\u4e00\u81f4\u3002\u7b54\u8fa9\u4e66\u5fc5\u987b\u5728\u4e0e\u539f\u8bf7\u613f\u4e66\u76f8\u540c\u7684\u6cd5\u9662\u548c\u53bf\u63d0\u4ea4\u3002", "common_errors": ["Filing in wrong court", "Wrong branch courthouse", "Address mismatch with FL-100"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL120-05", "label_en": "Petitioner / Respondent Names", "section": "header", "type": "text", "required": true, "guidance_en": "Must exactly match the Petitioner and Respondent names on the FL-100 and FL-110. Do NOT reverse the party designations \u2014 the original Petitioner remains Petitioner.", "guidance_es": "Debe coincidir exactamente con los nombres del Peticionario y Demandado en el FL-100 y FL-110. NO invierta las designaciones \u2014 el Peticionario original sigue siendo Peticionario.", "guidance_zh": "\u5fc5\u987b\u4e0eFL-100\u548cFL-110\u4e0a\u7684\u8bf7\u613f\u4eba\u548c\u88ab\u544a\u59d3\u540d\u5b8c\u5168\u4e00\u81f4\u3002\u4e0d\u8981\u98a0\u5012\u5f53\u4e8b\u4eba\u79f0\u8c13\u2014\u2014\u539f\u8bf7\u613f\u4eba\u4ecd\u4e3a\u8bf7\u613f\u4eba\u3002", "common_errors": ["Reversing Petitioner/Respondent roles", "Name spelling inconsistency across forms"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL120-06", "label_en": "Case Number", "section": "header", "type": "text", "required": true, "guidance_en": "Enter the case number assigned when the FL-100 was filed. This number appears on the summons (FL-110) you were served.", "guidance_es": "Ingrese el n\u00famero de caso asignado cuando se present\u00f3 el FL-100. Este n\u00famero aparece en la citaci\u00f3n (FL-110) que recibi\u00f3.", "guidance_zh": "\u8f93\u5165FL-100\u7acb\u6848\u65f6\u5206\u914d\u7684\u6848\u4ef6\u7f16\u53f7\u3002\u6b64\u7f16\u53f7\u663e\u793a\u5728\u60a8\u6536\u5230\u7684\u4f20\u7968\uff08FL-110\uff09\u4e0a\u3002", "common_errors": ["Wrong case number", "Using case number from different proceeding"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL120-07", "label_en": "Item 1 \u2014 Legal Relationship (Response)", "section": "body", "type": "checkbox_group", "required": true, "options": ["Dissolution (Divorce) of Marriage", "Legal Separation of Marriage", "Nullity (Annulment) of Marriage", "Dissolution of Domestic Partnership", "Legal Separation of Domestic Partnership", "Nullity of Domestic Partnership"], "guidance_en": "The Respondent may AGREE with the Petitioner''s request or REQUEST A DIFFERENT TYPE of proceeding. For example, if the Petitioner requested dissolution, the Respondent can request legal separation instead. The court will consider both requests.", "guidance_es": "El Demandado puede ESTAR DE ACUERDO con la solicitud del Peticionario o SOLICITAR UN TIPO DIFERENTE de procedimiento. Por ejemplo, si el Peticionario solicit\u00f3 disoluci\u00f3n, el Demandado puede solicitar separaci\u00f3n legal.", "guidance_zh": "\u88ab\u544a\u53ef\u4ee5\u540c\u610f\u8bf7\u613f\u4eba\u7684\u8bf7\u6c42\uff0c\u4e5f\u53ef\u4ee5\u8bf7\u6c42\u4e0d\u540c\u7c7b\u578b\u7684\u7a0b\u5e8f\u3002\u4f8b\u5982\uff0c\u5982\u679c\u8bf7\u613f\u4eba\u8bf7\u6c42\u89e3\u9664\u5a5a\u59fb\uff0c\u88ab\u544a\u53ef\u4ee5\u8bf7\u6c42\u5408\u6cd5\u5206\u5c45\u3002\u6cd5\u9662\u5c06\u8003\u8651\u53cc\u65b9\u8bf7\u6c42\u3002", "common_errors": ["Not understanding respondent can request different relief", "Leaving blank assumes agreement with petition"], "statutory_basis": "FAM \u00a72310"}, {"field_id": "FL120-08", "label_en": "Item 2 \u2014 Residency Requirement", "section": "body", "type": "checkbox_group", "required": true, "options": ["Petitioner satisfies residency requirements", "Respondent satisfies residency requirements", "Neither satisfies residency \u2014 legal separation only"], "guidance_en": "Respondent confirms or disputes whether residency requirements are met. If Respondent believes Petitioner filed in wrong county, this is where to flag it.", "guidance_es": "El Demandado confirma o disputa si se cumplen los requisitos de residencia.", "guidance_zh": "\u88ab\u544a\u786e\u8ba4\u6216\u8d28\u7591\u662f\u5426\u6ee1\u8db3\u5c45\u4f4f\u8981\u6c42\u3002\u5982\u88ab\u544a\u8ba4\u4e3a\u8bf7\u613f\u4eba\u5728\u9519\u8bef\u7684\u53bf\u63d0\u4ea4\uff0c\u5e94\u5728\u6b64\u6807\u6ce8\u3002", "common_errors": ["Not challenging residency when Petitioner doesn''t meet requirements", "Not understanding this is a venue challenge opportunity"], "statutory_basis": "FAM \u00a72320"}, {"field_id": "FL120-09", "label_en": "Item 3 \u2014 Statistical Facts", "section": "body", "type": "compound", "required": true, "subfields": ["Date of marriage/partnership", "Date of separation", "Time from marriage to separation"], "guidance_en": "Respondent enters their understanding of the dates. If dates DIFFER from the Petition, this creates a disputed issue that must be resolved. The date of separation is often contested \u2014 it affects community property cutoff and support duration.", "guidance_es": "El Demandado ingresa su comprensi\u00f3n de las fechas. Si las fechas DIFIEREN de la Petici\u00f3n, esto crea un tema disputado que debe resolverse.", "guidance_zh": "\u88ab\u544a\u8f93\u5165\u5176\u7406\u89e3\u7684\u65e5\u671f\u3002\u5982\u679c\u65e5\u671f\u4e0e\u8bf7\u613f\u4e66\u4e0d\u540c\uff0c\u5219\u4ea7\u751f\u9700\u8981\u89e3\u51b3\u7684\u4e89\u8bae\u4e8b\u9879\u3002\u5206\u5c45\u65e5\u671f\u7ecf\u5e38\u6709\u4e89\u8bae\u2014\u2014\u5b83\u5f71\u54cd\u5171\u540c\u8d22\u4ea7\u622a\u6b62\u65e5\u671f\u548c\u8d61\u517b\u8d39\u671f\u9650\u3002", "common_errors": ["Not disputing incorrect date of separation", "Not understanding impact of separation date on property division", "Agreeing to inaccurate dates without review"], "statutory_basis": "FAM \u00a770, FAM \u00a72550"}, {"field_id": "FL120-10", "label_en": "Item 4 \u2014 Minor Children", "section": "body", "type": "checkbox_group", "required": true, "options": ["There are no minor children", "The minor children are (list)", "A completed FL-105 must be attached", "Continued on Attachment 4"], "guidance_en": "Must match or correct the children listed on the FL-100. If the Petitioner omitted a child or listed incorrect information, the Respondent should correct it here. The FL-105 (UCCJEA) is MANDATORY if children are involved.", "guidance_es": "Debe coincidir o corregir los hijos listados en el FL-100. Si el Peticionario omiti\u00f3 un hijo o list\u00f3 informaci\u00f3n incorrecta, el Demandado debe corregirlo aqu\u00ed.", "guidance_zh": "\u5fc5\u987b\u4e0eFL-100\u4e0a\u5217\u51fa\u7684\u5b50\u5973\u4fe1\u606f\u4e00\u81f4\u6216\u8fdb\u884c\u66f4\u6b63\u3002\u5982\u8bf7\u613f\u4eba\u9057\u6f0f\u5b50\u5973\u6216\u5217\u51fa\u4e0d\u6b63\u786e\u4fe1\u606f\uff0c\u88ab\u544a\u5e94\u5728\u6b64\u66f4\u6b63\u3002\u5982\u6d89\u53ca\u5b50\u5973\uff0cFL-105\uff08UCCJEA\uff09\u4e3a\u5f3a\u5236\u6027\u9644\u4ef6\u3002", "common_errors": ["Not correcting Petitioner''s errors about children", "Omitting FL-105", "Not listing all minor children from the relationship"], "statutory_basis": "FAM \u00a73400, FAM \u00a73402"}, {"field_id": "FL120-11", "label_en": "Item 5 \u2014 Spousal/Partner Support", "section": "body", "type": "checkbox_group", "required": true, "options": ["Spousal support payable to Petitioner", "Spousal support payable to Respondent", "Terminate ability to award support to Petitioner", "Terminate ability to award support to Respondent", "Reserve jurisdiction"], "guidance_en": "Respondent states their own requests regarding spousal support. This may agree with or oppose the Petitioner''s requests. CRITICAL: Terminating the right to support is PERMANENT and IRREVERSIBLE. If unsure, RESERVE jurisdiction.", "guidance_es": "El Demandado declara sus propias solicitudes respecto a la manutenci\u00f3n conyugal. CR\u00cdTICO: Terminar el derecho a manutenci\u00f3n es PERMANENTE e IRREVERSIBLE. Si no est\u00e1 seguro, RESERVE jurisdicci\u00f3n.", "guidance_zh": "\u88ab\u544a\u9648\u8ff0\u5176\u5173\u4e8e\u914d\u5076\u8d61\u517b\u8d39\u7684\u8bf7\u6c42\u3002\u53ef\u4ee5\u540c\u610f\u6216\u53cd\u5bf9\u8bf7\u613f\u4eba\u7684\u8bf7\u6c42\u3002\u5173\u952e\uff1a\u7ec8\u6b62\u8d61\u517b\u6743\u662f\u6c38\u4e45\u4e14\u4e0d\u53ef\u9006\u7684\u3002\u5982\u4e0d\u786e\u5b9a\uff0c\u8bf7\u4fdd\u7559\u7ba1\u8f96\u6743\u3002", "common_errors": ["Accidentally waiving right to future support", "Not requesting support when entitled", "Checking conflicting options"], "statutory_basis": "FAM \u00a74330, FAM \u00a74336"}, {"field_id": "FL120-12", "label_en": "Item 6 \u2014 Separate Property", "section": "body", "type": "checkbox", "required": false, "guidance_en": "Respondent can request confirmation of their separate property. This is the Respondent''s opportunity to identify assets and debts that should NOT be divided as community property.", "guidance_es": "El Demandado puede solicitar la confirmaci\u00f3n de su propiedad separada.", "guidance_zh": "\u88ab\u544a\u53ef\u4ee5\u8981\u6c42\u786e\u8ba4\u5176\u4e2a\u4eba\u8d22\u4ea7\u3002\u8fd9\u662f\u88ab\u544a\u8bc6\u522b\u4e0d\u5e94\u4f5c\u4e3a\u5171\u540c\u8d22\u4ea7\u5206\u5272\u7684\u8d44\u4ea7\u548c\u503a\u52a1\u7684\u673a\u4f1a\u3002", "common_errors": ["Not identifying separate property at this stage"], "statutory_basis": "FAM \u00a7770, FAM \u00a72550"}, {"field_id": "FL120-13", "label_en": "Item 7 \u2014 Community/Quasi-Community Property", "section": "body", "type": "checkbox_group", "required": false, "options": ["Determine property rights", "Award community assets to parties", "One-half to each"], "guidance_en": "Respondent''s request regarding community property division. California default is equal (50/50) division.", "guidance_es": "Solicitud del Demandado respecto a la divisi\u00f3n de propiedad comunitaria. El valor predeterminado de California es divisi\u00f3n igualitaria (50/50).", "guidance_zh": "\u88ab\u544a\u5173\u4e8e\u5171\u540c\u8d22\u4ea7\u5206\u5272\u7684\u8bf7\u6c42\u3002\u52a0\u5229\u798f\u5c3c\u4e9a\u9ed8\u8ba4\u4e3a\u5e73\u5747\uff0850/50\uff09\u5206\u5272\u3002", "common_errors": ["Not understanding all community assets must be disclosed", "Agreeing to unequal division without legal basis"], "statutory_basis": "FAM \u00a72550"}, {"field_id": "FL120-14", "label_en": "Item 8 \u2014 Other Requests", "section": "body", "type": "checkbox_group", "required": false, "options": ["Attorney fees and costs", "Respondent''s former name restored to", "Other (specify)"], "guidance_en": "Respondent can request attorney fees under FAM \u00a72030, name restoration, or other relief. The Respondent CAN request relief even if the Petitioner did not \u2014 the Response is an independent pleading.", "guidance_es": "El Demandado puede solicitar honorarios de abogado bajo FAM \u00a72030, restauraci\u00f3n de nombre u otro alivio.", "guidance_zh": "\u88ab\u544a\u53ef\u6839\u636eFAM \u00a72030\u8bf7\u6c42\u5f8b\u5e08\u8d39\u3001\u6062\u590d\u59d3\u540d\u6216\u5176\u4ed6\u6551\u6d4e\u3002\u5373\u4f7f\u8bf7\u613f\u4eba\u672a\u8bf7\u6c42\uff0c\u88ab\u544a\u4e5f\u53ef\u72ec\u7acb\u8bf7\u6c42\u3002", "common_errors": ["Not requesting attorney fees when income disparity exists", "Not understanding Response is an independent pleading"], "statutory_basis": "FAM \u00a72030"}, {"field_id": "FL120-15", "label_en": "Item 9 \u2014 Child Custody", "section": "body", "type": "checkbox_group", "required": false, "options": ["Legal custody to Petitioner", "Legal custody to Respondent", "Joint legal custody", "Physical custody to Petitioner", "Physical custody to Respondent", "Joint physical custody", "Visitation to Petitioner", "Visitation to Respondent", "As stated in attached FL-311"], "guidance_en": "Respondent''s custody requests. May agree with or oppose the Petitioner. Attach FL-311 for detailed custody/visitation plan. The court will apply the ''best interest of the child'' standard (FAM \u00a73011).", "guidance_es": "Solicitudes de custodia del Demandado. Puede estar de acuerdo o en oposici\u00f3n al Peticionario. Adjunte FL-311 para un plan detallado.", "guidance_zh": "\u88ab\u544a\u7684\u76d1\u62a4\u6743\u8bf7\u6c42\u3002\u53ef\u4ee5\u540c\u610f\u6216\u53cd\u5bf9\u8bf7\u613f\u4eba\u3002\u9644\u4e0aFL-311\u4ee5\u63d0\u4f9b\u8be6\u7ec6\u7684\u76d1\u62a4/\u63a2\u89c6\u8ba1\u5212\u3002\u6cd5\u9662\u5c06\u9002\u7528''\u5b50\u5973\u6700\u4f73\u5229\u76ca''\u6807\u51c6\uff08FAM \u00a73011\uff09\u3002", "common_errors": ["Not attaching FL-311 when detailed orders needed", "Not addressing custody when children are involved", "Confusing legal and physical custody"], "statutory_basis": "FAM \u00a73011, FAM \u00a73020, FAM \u00a73040"}, {"field_id": "FL120-16", "label_en": "Item 10 \u2014 Child Support", "section": "body", "type": "checkbox", "required": false, "guidance_en": "Respondent can request child support. California uses a mandatory guideline formula (FAM \u00a74055). Both parties'' incomes and timeshare percentage are used in the calculation.", "guidance_es": "El Demandado puede solicitar manutenci\u00f3n de menores. California usa una f\u00f3rmula gu\u00eda obligatoria (FAM \u00a74055).", "guidance_zh": "\u88ab\u544a\u53ef\u4ee5\u8bf7\u6c42\u5b50\u5973\u629a\u517b\u8d39\u3002\u52a0\u5229\u798f\u5c3c\u4e9a\u4f7f\u7528\u5f3a\u5236\u6027\u6307\u5bfc\u516c\u5f0f\uff08FAM \u00a74055\uff09\u3002\u53cc\u65b9\u6536\u5165\u548c\u65f6\u95f4\u5206\u914d\u767e\u5206\u6bd4\u7528\u4e8e\u8ba1\u7b97\u3002", "common_errors": ["Not requesting support when entitled", "Not understanding guideline formula"], "statutory_basis": "FAM \u00a74050, FAM \u00a74055"}, {"field_id": "FL120-17", "label_en": "Declaration Under Penalty of Perjury", "section": "signature", "type": "signature_block", "required": true, "guidance_en": "Sign and date under penalty of perjury. Your signature certifies all information is true and correct. Must include city and state where signed.", "guidance_es": "Firme y feche bajo pena de perjurio. Su firma certifica que toda la informaci\u00f3n es verdadera y correcta.", "guidance_zh": "\u5728\u4f2a\u8bc1\u5904\u7f5a\u6761\u6b3e\u4e0b\u7b7e\u540d\u5e76\u6ce8\u660e\u65e5\u671f\u3002\u60a8\u7684\u7b7e\u540d\u8bc1\u660e\u6240\u6709\u4fe1\u606f\u771f\u5b9e\u6b63\u786e\u3002\u5fc5\u987b\u5305\u62ec\u7b7e\u7f72\u5730\u7684\u57ce\u5e02\u548c\u5dde\u3002", "common_errors": ["Forgetting to sign", "Wrong date", "Missing city/state"], "statutory_basis": "CCP \u00a72015.5"}, {"field_id": "FL120-18", "label_en": "Filing Deadline", "section": "procedural", "type": "informational", "required": false, "guidance_en": "The Response MUST be filed within 30 calendar days of personal service of the Summons and Petition. If served by notice and acknowledgment of receipt, 30 days from the date of signing the acknowledgment. Failure to file a timely response may result in a DEFAULT judgment \u2014 the court may grant everything the Petitioner requested without your input.", "guidance_es": "La Respuesta DEBE presentarse dentro de 30 d\u00edas calendario de la notificaci\u00f3n personal de la Citaci\u00f3n y Petici\u00f3n. No presentar una respuesta oportuna puede resultar en un fallo en REBELD\u00cdA.", "guidance_zh": "\u7b54\u8fa9\u4e66\u5fc5\u987b\u5728\u4eb2\u81ea\u9001\u8fbe\u4f20\u7968\u548c\u8bf7\u613f\u4e66\u540e30\u4e2a\u65e5\u5386\u65e5\u5185\u63d0\u4ea4\u3002\u672a\u80fd\u53ca\u65f6\u63d0\u4ea4\u7b54\u8fa9\u4e66\u53ef\u80fd\u5bfc\u81f4\u7f3a\u5e2d\u5224\u51b3\u2014\u2014\u6cd5\u9662\u53ef\u80fd\u5728\u65e0\u60a8\u53c2\u4e0e\u7684\u60c5\u51b5\u4e0b\u6279\u51c6\u8bf7\u613f\u4eba\u7684\u6240\u6709\u8bf7\u6c42\u3002", "common_errors": ["Missing the 30-day deadline", "Not understanding default consequences", "Confusing service date with filing date", "Not filing fee waiver to preserve deadline"], "statutory_basis": "CCP \u00a7412.20, CCP \u00a7585"}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-150', 'FL-150', 'FL-150', 'A', 'California Courts', 0, '["en","es","zh"]', '{"form_id": "FL-150", "title_en": "Income and Expense Declaration", "tier": "B", "version": "1.0.0", "created": "2026-02-25", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "project": "VERNEN\u2122 Guided Document Navigator", "governing_statutes": ["FAM \u00a72030", "FAM \u00a73620", "FAM \u00a74058", "CRC 5.260"], "purpose": {"en": "Discloses income, expenses, and financial obligations to the court. Required in most cases involving child support, spousal support, or attorney fees requests. Must be current within the last 3 months.", "es": "Divulga ingresos, gastos y obligaciones financieras al tribunal. Requerido en la mayor\u00eda de los casos que involucran manutenci\u00f3n de menores, manutenci\u00f3n conyugal o solicitudes de honorarios de abogados. Debe estar actualizado dentro de los \u00faltimos 3 meses.", "zh": "\u5411\u6cd5\u9662\u62ab\u9732\u6536\u5165\u3001\u652f\u51fa\u548c\u8d22\u52a1\u4e49\u52a1\u3002\u5728\u6d89\u53ca\u5b50\u5973\u629a\u517b\u8d39\u3001\u914d\u5076\u8d61\u517b\u8d39\u6216\u5f8b\u5e08\u8d39\u8bf7\u6c42\u7684\u5927\u591a\u6570\u6848\u4ef6\u4e2d\u9700\u8981\u3002\u5fc5\u987b\u5728\u6700\u8fd13\u4e2a\u6708\u5185\u66f4\u65b0\u3002", "vi": "C\u00f4ng b\u1ed1 thu nh\u1eadp, chi ph\u00ed v\u00e0 ngh\u0129a v\u1ee5 t\u00e0i ch\u00ednh cho t\u00f2a \u00e1n. B\u1eaft bu\u1ed9c trong h\u1ea7u h\u1ebft c\u00e1c tr\u01b0\u1eddng h\u1ee3p li\u00ean quan \u0111\u1ebfn c\u1ea5p d\u01b0\u1ee1ng nu\u00f4i con, c\u1ea5p d\u01b0\u1ee1ng v\u1ee3/ch\u1ed3ng ho\u1eb7c y\u00eau c\u1ea7u ph\u00ed lu\u1eadt s\u01b0. Ph\u1ea3i c\u1eadp nh\u1eadt trong v\u00f2ng 3 th\u00e1ng g\u1ea7n nh\u1ea5t.", "so": "Waxay shaaca ka qaadaysaa dakhliga, kharashka iyo waajibyadda maaliyadda ee maxkamadda. Waa loo baahan yahay kiisaska badankooda ee ku lug leh taageerada ilmaha, taageerada xaaska ama codsiyada khidmadda qareenka. Waa inay taariikhdu noqotaa 3 bilood ee ugu dambeeyay.", "ti": "\u12a3\u1273\u12ca\u1363 \u12c8\u133b\u12a2 \u1295 \u1293\u12ed \u1308\u1295\u12d8\u1263\u12ca \u130d\u12f4\u1273\u1273\u1275 \u1295\u1264\u1275 \u134d\u122d\u12f2 \u12e8\u1255\u122d\u1265\u1362 \u12a3\u1265 \u1218\u1265\u12db\u1215\u1275\u12a1 \u1309\u12f3\u12eb\u1275 \u1293\u12ed \u1215\u133b\u1293\u1275 \u12f0\u1308\u134d\u1363 \u1293\u12ed \u1260\u12d3\u120d/\u1272 \u1213\u12f3\u122d \u12f0\u1308\u134d \u12c8\u12ed \u1293\u12ed \u1320\u1260\u1253 \u12ad\u134d\u120a\u1275 \u1320\u1208\u1263\u1275 \u12dd\u1213\u12d9 \u12ed\u12f5\u1208\u1362 \u12a3\u1265 \u12cd\u123d\u1322 3 \u12a3\u12cb\u122d\u1215 \u12dd\u1213\u1208\u1348 \u12ad\u12d5\u12f0\u1235 \u12a3\u1208\u12ce\u1362", "am": "\u1308\u1262\u1295\u1363 \u12c8\u132a\u1295 \u12a5\u1293 \u12e8\u1308\u1295\u12d8\u1265 \u130d\u12f4\u1273\u12ce\u127d\u1295 \u1208\u134d\u122d\u12f5 \u1264\u1275 \u12eb\u1233\u12cd\u1243\u120d\u1362 \u12e8\u120d\u1305 \u12f5\u130b\u134d\u1363 \u12e8\u1275\u12f3\u122d \u1313\u12f0\u129b \u12f5\u130b\u134d \u12c8\u12ed\u121d \u12e8\u1320\u1260\u1243 \u12ad\u134d\u12eb \u1325\u12eb\u1244\u12ce\u127d\u1295 \u12e8\u121a\u12eb\u12ab\u1275\u1271 \u12a0\u1265\u12db\u129b\u12ce\u1279 \u1309\u12f3\u12ee\u127d \u12ed\u1348\u120d\u130b\u1209\u1362 \u1263\u1208\u1349\u1275 3 \u12c8\u122b\u1275 \u12cd\u1235\u1325 \u12d8\u1218\u1293\u12ca \u1218\u1206\u1295 \u12a0\u1208\u1260\u1275\u1362", "ar": "\u064a\u0643\u0634\u0641 \u0639\u0646 \u0627\u0644\u062f\u062e\u0644 \u0648\u0627\u0644\u0646\u0641\u0642\u0627\u062a \u0648\u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645\u0627\u062a \u0627\u0644\u0645\u0627\u0644\u064a\u0629 \u0644\u0644\u0645\u062d\u0643\u0645\u0629. \u0645\u0637\u0644\u0648\u0628 \u0641\u064a \u0645\u0639\u0638\u0645 \u0627\u0644\u0642\u0636\u0627\u064a\u0627 \u0627\u0644\u0645\u062a\u0639\u0644\u0642\u0629 \u0628\u0646\u0641\u0642\u0629 \u0627\u0644\u0623\u0637\u0641\u0627\u0644 \u0623\u0648 \u0646\u0641\u0642\u0629 \u0627\u0644\u0632\u0648\u062c \u0623\u0648 \u0637\u0644\u0628\u0627\u062a \u0623\u062a\u0639\u0627\u0628 \u0627\u0644\u0645\u062d\u0627\u0645\u0627\u0629. \u064a\u062c\u0628 \u0623\u0646 \u064a\u0643\u0648\u0646 \u0645\u062d\u062f\u062b\u0627\u064b \u062e\u0644\u0627\u0644 \u0627\u0644\u0623\u0634\u0647\u0631 \u0627\u0644\u062b\u0644\u0627\u062b\u0629 \u0627\u0644\u0645\u0627\u0636\u064a\u0629.", "ht": "Devwale revni, depans, ak obligasyon finansye bay tribinal la. Obligatwa nan pif\u00f2 ka ki gen rap\u00f2 ak sip\u00f2 timoun, sip\u00f2 konjwen, oswa demann fr\u00e8 avoka. Dwe ajou nan d\u00e8ny\u00e9 3 mwa yo.", "ko": "\ubc95\uc6d0\uc5d0 \uc18c\ub4dd, \uc9c0\ucd9c \ubc0f \uc7ac\uc815\uc801 \uc758\ubb34\ub97c \uacf5\uac1c\ud569\ub2c8\ub2e4. \uc790\ub140 \uc591\uc721\ube44, \ubc30\uc6b0\uc790 \ubd80\uc591\ube44 \ub610\ub294 \ubcc0\ud638\uc0ac \ube44\uc6a9 \uc694\uccad\uacfc \uad00\ub828\ub41c \ub300\ubd80\ubd84\uc758 \uc0ac\uac74\uc5d0\uc11c \ud544\uc694\ud569\ub2c8\ub2e4. \ucd5c\uadfc 3\uac1c\uc6d4 \uc774\ub0b4\uc5d0 \uc5c5\ub370\uc774\ud2b8\ud574\uc57c \ud569\ub2c8\ub2e4.", "pt": "Divulga renda, despesas e obriga\u00e7\u00f5es financeiras ao tribunal. Necess\u00e1rio na maioria dos casos envolvendo pens\u00e3o aliment\u00edcia, pens\u00e3o para c\u00f4njuge ou pedidos de honor\u00e1rios advocat\u00edcios. Deve estar atualizado nos \u00faltimos 3 meses.", "ru": "\u0420\u0430\u0441\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0434\u043e\u0445\u043e\u0434\u044b, \u0440\u0430\u0441\u0445\u043e\u0434\u044b \u0438 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u044b\u0435 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0441\u0443\u0434\u0443. \u0422\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044f \u0432 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u0435 \u0434\u0435\u043b, \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0445 \u0441 \u0430\u043b\u0438\u043c\u0435\u043d\u0442\u0430\u043c\u0438 \u043d\u0430 \u0434\u0435\u0442\u0435\u0439, \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435\u043c \u0441\u0443\u043f\u0440\u0443\u0433\u0430 \u0438\u043b\u0438 \u0437\u0430\u043f\u0440\u043e\u0441\u0430\u043c\u0438 \u043d\u0430 \u043e\u043f\u043b\u0430\u0442\u0443 \u0430\u0434\u0432\u043e\u043a\u0430\u0442\u0430. \u0414\u043e\u043b\u0436\u043d\u0430 \u0431\u044b\u0442\u044c \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0430 \u0432 \u0442\u0435\u0447\u0435\u043d\u0438\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0445 3 \u043c\u0435\u0441\u044f\u0446\u0435\u0432.", "tl": "Ibinubunyag ang kita, gastos, at mga obligasyong pinansyal sa korte. Kinakailangan sa karamihan ng mga kaso na may kaugnayan sa suporta ng bata, suporta ng asawa, o kahilingan sa bayad ng abogado. Dapat na napapanahon sa loob ng huling 3 buwan."}, "sections": [{"section_id": "header", "fields": [{"field_id": "attorney_or_party", "label_en": "Attorney or Party Without Attorney", "type": "text", "required": true, "annotations": {"en": "Enter your full legal name, address, phone number, and email. If you have an attorney, enter their information and State Bar number.", "es": "Ingrese su nombre legal completo, direcci\u00f3n, tel\u00e9fono y correo electr\u00f3nico. Si tiene abogado, ingrese su informaci\u00f3n y n\u00famero del Colegio de Abogados.", "zh": "\u8f93\u5165\u60a8\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u3001\u5730\u5740\u3001\u7535\u8bdd\u548c\u7535\u5b50\u90ae\u4ef6\u3002\u5982\u679c\u60a8\u6709\u5f8b\u5e08\uff0c\u8bf7\u8f93\u5165\u5f8b\u5e08\u7684\u4fe1\u606f\u548c\u5dde\u5f8b\u5e08\u516c\u4f1a\u7f16\u53f7\u3002"}}, {"field_id": "case_number", "label_en": "Case Number", "type": "text", "required": true, "annotations": {"en": "Enter the case number assigned by the court. This must match exactly across all filings.", "es": "Ingrese el n\u00famero de caso asignado por el tribunal. Debe coincidir exactamente en todos los documentos.", "zh": "\u8f93\u5165\u6cd5\u9662\u5206\u914d\u7684\u6848\u4ef6\u7f16\u53f7\u3002\u6b64\u7f16\u53f7\u5fc5\u987b\u5728\u6240\u6709\u6587\u4ef6\u4e2d\u5b8c\u5168\u4e00\u81f4\u3002"}}]}, {"section_id": "employment", "section_title_en": "Employment Information", "fields": [{"field_id": "employment_status", "label_en": "Employment Status", "type": "checkbox_group", "required": true, "options": ["employed", "self_employed", "unemployed", "retired"], "annotations": {"en": "Check your current employment status. If unemployed, you must explain efforts to find work. If self-employed, attach business records.", "es": "Marque su estado de empleo actual. Si est\u00e1 desempleado, debe explicar sus esfuerzos para encontrar trabajo. Si trabaja por cuenta propia, adjunte registros comerciales.", "zh": "\u52fe\u9009\u60a8\u5f53\u524d\u7684\u5c31\u4e1a\u72b6\u6001\u3002\u5982\u679c\u5931\u4e1a\uff0c\u5fc5\u987b\u8bf4\u660e\u6c42\u804c\u52aa\u529b\u3002\u5982\u679c\u662f\u81ea\u96c7\u4eba\u58eb\uff0c\u8bf7\u9644\u4e0a\u4e1a\u52a1\u8bb0\u5f55\u3002"}}, {"field_id": "employer_info", "label_en": "Employer Name and Address", "type": "text", "required": true, "condition": "employment_status == ''employed''", "annotations": {"en": "Full name and address of your current employer. Include all employers if you hold multiple jobs.", "es": "Nombre completo y direcci\u00f3n de su empleador actual. Incluya todos los empleadores si tiene varios trabajos.", "zh": "\u60a8\u5f53\u524d\u96c7\u4e3b\u7684\u5168\u540d\u548c\u5730\u5740\u3002\u5982\u679c\u6709\u591a\u4efd\u5de5\u4f5c\uff0c\u8bf7\u5305\u62ec\u6240\u6709\u96c7\u4e3b\u3002"}}, {"field_id": "occupation", "label_en": "Occupation", "type": "text", "required": true, "annotations": {"en": "Your job title or occupation. Be specific (e.g., ''commercial plumber'' not just ''construction'').", "es": "Su t\u00edtulo de trabajo u ocupaci\u00f3n. Sea espec\u00edfico (por ejemplo, ''plomero comercial'' no solo ''construcci\u00f3n'').", "zh": "\u60a8\u7684\u804c\u4f4d\u6216\u804c\u4e1a\u3002\u8bf7\u5177\u4f53\u8bf4\u660e\uff08\u4f8b\u5982\uff0c''\u5546\u4e1a\u7ba1\u9053\u5de5''\u800c\u4e0d\u4ec5\u4ec5\u662f''\u5efa\u7b51''\uff09\u3002"}}, {"field_id": "date_job_started", "label_en": "Date Job Started", "type": "date", "required": true, "annotations": {"en": "Date you began your current employment. Month and year are sufficient.", "es": "Fecha en que comenz\u00f3 su empleo actual. Mes y a\u00f1o son suficientes.", "zh": "\u60a8\u5f00\u59cb\u5f53\u524d\u5de5\u4f5c\u7684\u65e5\u671f\u3002\u6708\u4efd\u548c\u5e74\u4efd\u5373\u53ef\u3002"}}]}, {"section_id": "income", "section_title_en": "Income Information", "fields": [{"field_id": "gross_monthly_income", "label_en": "Gross Monthly Income", "type": "currency", "required": true, "annotations": {"en": "Total income BEFORE taxes and deductions. Include salary/wages from all sources. This is the most critical number on this form \u2014 courts use it to calculate support obligations under FAM \u00a7 4058.", "es": "Ingreso total ANTES de impuestos y deducciones. Incluya salario/sueldos de todas las fuentes. Este es el n\u00famero m\u00e1s cr\u00edtico en este formulario \u2014 los tribunales lo usan para calcular obligaciones de manutenci\u00f3n bajo FAM \u00a7 4058.", "zh": "\u7a0e\u524d\u548c\u6263\u9664\u524d\u7684\u603b\u6536\u5165\u3002\u5305\u62ec\u6240\u6709\u6765\u6e90\u7684\u85aa\u8d44/\u5de5\u8d44\u3002\u8fd9\u662f\u6b64\u8868\u683c\u4e2d\u6700\u5173\u952e\u7684\u6570\u5b57\u2014\u2014\u6cd5\u9662\u6839\u636eFAM \u00a7 4058\u4f7f\u7528\u5b83\u6765\u8ba1\u7b97\u8d61\u517b\u4e49\u52a1\u3002"}}, {"field_id": "pay_period", "label_en": "Pay Period", "type": "radio", "required": true, "options": ["weekly", "biweekly", "semimonthly", "monthly"], "annotations": {"en": "How often you are paid. Weekly = every week, Biweekly = every 2 weeks, Semimonthly = twice per month, Monthly = once per month.", "es": "Con qu\u00e9 frecuencia le pagan. Semanal = cada semana, Quincenal = cada 2 semanas, Bimensual = dos veces al mes, Mensual = una vez al mes.", "zh": "\u60a8\u83b7\u5f97\u62a5\u916c\u7684\u9891\u7387\u3002\u6bcf\u5468=\u6bcf\u5468\u4e00\u6b21\uff0c\u53cc\u5468=\u6bcf\u4e24\u5468\u4e00\u6b21\uff0c\u534a\u6708=\u6bcf\u6708\u4e24\u6b21\uff0c\u6bcf\u6708=\u6bcf\u6708\u4e00\u6b21\u3002"}}, {"field_id": "attach_pay_stubs", "label_en": "Attach Last 2 Months Pay Stubs", "type": "attachment", "required": true, "annotations": {"en": "MANDATORY: You MUST attach your last 2 months of pay stubs. Failure to attach pay stubs can result in sanctions or adverse inferences about your income.", "es": "OBLIGATORIO: DEBE adjuntar sus \u00faltimos 2 meses de recibos de pago. No adjuntar recibos de pago puede resultar en sanciones o inferencias adversas sobre sus ingresos.", "zh": "\u5f3a\u5236\u8981\u6c42\uff1a\u60a8\u5fc5\u987b\u9644\u4e0a\u6700\u8fd12\u4e2a\u6708\u7684\u5de5\u8d44\u5355\u3002\u672a\u80fd\u9644\u4e0a\u5de5\u8d44\u5355\u53ef\u80fd\u5bfc\u81f4\u5236\u88c1\u6216\u5bf9\u60a8\u6536\u5165\u7684\u4e0d\u5229\u63a8\u65ad\u3002"}}, {"field_id": "other_income", "label_en": "Other Monthly Income", "type": "currency_itemized", "required": false, "items": ["investment_income", "rental_income", "trust_income", "social_security", "disability", "unemployment", "workers_compensation", "spousal_support_received", "other_sources"], "annotations": {"en": "List ALL other sources of income. Under FAM \u00a7 4058(a), income includes virtually all money received from any source.", "es": "Enumere TODAS las dem\u00e1s fuentes de ingresos. Bajo FAM \u00a7 4058(a), el ingreso incluye virtualmente todo dinero recibido de cualquier fuente.", "zh": "\u5217\u51fa\u6240\u6709\u5176\u4ed6\u6536\u5165\u6765\u6e90\u3002\u6839\u636eFAM \u00a7 4058(a)\uff0c\u6536\u5165\u5305\u62ec\u51e0\u4e4e\u4ece\u4efb\u4f55\u6765\u6e90\u6536\u5230\u7684\u6240\u6709\u6b3e\u9879\u3002"}}]}, {"section_id": "deductions", "section_title_en": "Tax and Mandatory Deductions", "fields": [{"field_id": "federal_taxes", "label_en": "Federal Income Tax", "type": "currency", "required": true, "annotations": {"en": "Amount withheld for federal income tax per month. Must match your pay stub.", "es": "Monto retenido para impuesto federal sobre la renta por mes. Debe coincidir con su recibo de pago.", "zh": "\u6bcf\u6708\u6263\u9664\u7684\u8054\u90a6\u6240\u5f97\u7a0e\u91d1\u989d\u3002\u5fc5\u987b\u4e0e\u5de5\u8d44\u5355\u4e00\u81f4\u3002"}}, {"field_id": "state_taxes", "label_en": "State Income Tax", "type": "currency", "required": true, "annotations": {"en": "California state income tax withheld per month.", "es": "Impuesto estatal de California retenido por mes.", "zh": "\u6bcf\u6708\u6263\u9664\u7684\u52a0\u5dde\u5dde\u6240\u5f97\u7a0e\u3002"}}, {"field_id": "social_security_fica", "label_en": "Social Security / FICA", "type": "currency", "required": true, "annotations": {"en": "Social Security and Medicare tax withheld per month. Standard rate is 7.65% of gross wages.", "es": "Impuesto del Seguro Social y Medicare retenido por mes. La tasa est\u00e1ndar es 7.65% del salario bruto.", "zh": "\u6bcf\u6708\u6263\u9664\u7684\u793e\u4f1a\u4fdd\u969c\u548c\u533b\u7597\u4fdd\u9669\u7a0e\u3002\u6807\u51c6\u7a0e\u7387\u4e3a\u603b\u5de5\u8d44\u76847.65%\u3002"}}, {"field_id": "health_insurance", "label_en": "Health Insurance Premiums", "type": "currency", "required": false, "annotations": {"en": "Monthly health insurance premiums deducted from your pay. Include only the employee portion.", "es": "Primas de seguro m\u00e9dico mensuales deducidas de su pago. Incluya solo la porci\u00f3n del empleado.", "zh": "\u4ece\u5de5\u8d44\u4e2d\u6263\u9664\u7684\u6bcf\u6708\u5065\u5eb7\u4fdd\u9669\u4fdd\u8d39\u3002\u4ec5\u5305\u62ec\u5458\u5de5\u90e8\u5206\u3002"}}, {"field_id": "union_dues", "label_en": "Union Dues", "type": "currency", "required": false, "annotations": {"en": "Monthly union dues if applicable. Include only mandatory dues, not voluntary contributions.", "es": "Cuotas sindicales mensuales si corresponde. Incluya solo cuotas obligatorias.", "zh": "\u5982\u9002\u7528\uff0c\u6bcf\u6708\u5de5\u4f1a\u4f1a\u8d39\u3002\u4ec5\u5305\u62ec\u5f3a\u5236\u6027\u4f1a\u8d39\u3002"}}]}, {"section_id": "expenses", "section_title_en": "Monthly Expenses", "fields": [{"field_id": "housing", "label_en": "Rent or Mortgage", "type": "currency", "required": true, "annotations": {"en": "Monthly rent or mortgage payment for your primary residence.", "es": "Pago mensual de alquiler o hipoteca de su residencia principal.", "zh": "\u60a8\u4e3b\u8981\u4f4f\u6240\u7684\u6bcf\u6708\u79df\u91d1\u6216\u62b5\u62bc\u8d37\u6b3e\u4ed8\u6b3e\u3002"}}, {"field_id": "food_household", "label_en": "Food and Household Supplies", "type": "currency", "required": true, "annotations": {"en": "Monthly cost for groceries and basic household supplies. Be realistic.", "es": "Costo mensual de alimentos y suministros b\u00e1sicos del hogar. Sea realista.", "zh": "\u98df\u54c1\u548c\u57fa\u672c\u5bb6\u5ead\u7528\u54c1\u7684\u6bcf\u6708\u8d39\u7528\u3002\u8981\u5b9e\u9645\u3002"}}, {"field_id": "utilities", "label_en": "Utilities", "type": "currency", "required": true, "annotations": {"en": "Monthly cost for electricity, gas, water, trash, phone, internet.", "es": "Costo mensual de electricidad, gas, agua, basura, tel\u00e9fono, internet.", "zh": "\u7535\u3001\u6c14\u3001\u6c34\u3001\u5783\u573e\u5904\u7406\u3001\u7535\u8bdd\u3001\u4e92\u8054\u7f51\u7684\u6bcf\u6708\u8d39\u7528\u3002"}}, {"field_id": "transportation", "label_en": "Transportation", "type": "currency", "required": true, "annotations": {"en": "Monthly transportation costs including car payment, insurance, gas, maintenance, or public transit.", "es": "Costos de transporte mensuales incluyendo pago de auto, seguro, gasolina, mantenimiento o transporte p\u00fablico.", "zh": "\u6bcf\u6708\u4ea4\u901a\u8d39\u7528\uff0c\u5305\u62ec\u6c7d\u8f66\u4ed8\u6b3e\u3001\u4fdd\u9669\u3001\u6c7d\u6cb9\u3001\u7ef4\u62a4\u6216\u516c\u5171\u4ea4\u901a\u3002"}}, {"field_id": "childcare", "label_en": "Child Care", "type": "currency", "required": false, "annotations": {"en": "Monthly childcare expenses. Under FAM \u00a7 4062, reasonable childcare costs related to employment are added to guideline support.", "es": "Gastos mensuales de cuidado infantil. Bajo FAM \u00a7 4062, los costos razonables se agregan al c\u00e1lculo de manutenci\u00f3n.", "zh": "\u6bcf\u6708\u513f\u7ae5\u4fdd\u80b2\u8d39\u7528\u3002\u6839\u636eFAM \u00a7 4062\uff0c\u4e0e\u5c31\u4e1a\u76f8\u5173\u7684\u5408\u7406\u4fdd\u80b2\u8d39\u7528\u5c06\u52a0\u5165\u6307\u5bfc\u6027\u629a\u517b\u8d39\u8ba1\u7b97\u3002"}}, {"field_id": "insurance", "label_en": "Insurance (not deducted from pay)", "type": "currency", "required": false, "annotations": {"en": "Insurance premiums you pay directly (not through payroll deduction). Include auto, renter''s/homeowner''s, life.", "es": "Primas de seguro que paga directamente (no a trav\u00e9s de deducci\u00f3n de n\u00f3mina).", "zh": "\u60a8\u76f4\u63a5\u652f\u4ed8\u7684\u4fdd\u9669\u4fdd\u8d39\uff08\u975e\u901a\u8fc7\u5de5\u8d44\u6263\u9664\uff09\u3002"}}]}, {"section_id": "hardship_deductions", "section_title_en": "Hardship Deductions", "fields": [{"field_id": "hardship_items", "label_en": "Hardship Deductions", "type": "itemized_list", "required": false, "annotations": {"en": "Under FAM \u00a7 4071, the court MAY allow hardship deductions for: (a) extraordinary health expenses; (b) uninsured catastrophic losses; (c) minimum basic living expenses of children from other relationships.", "es": "Bajo FAM \u00a7 4071, el tribunal PUEDE permitir deducciones por dificultades para: (a) gastos de salud extraordinarios; (b) p\u00e9rdidas catastr\u00f3ficas no aseguradas; (c) gastos b\u00e1sicos m\u00ednimos de hijos de otras relaciones.", "zh": "\u6839\u636eFAM \u00a7 4071\uff0c\u6cd5\u9662\u53ef\u4ee5\u5141\u8bb8\u56f0\u96be\u6263\u9664\u7528\u4e8e\uff1a(a) \u7279\u6b8a\u533b\u7597\u8d39\u7528\uff1b(b) \u672a\u6295\u4fdd\u7684\u707e\u96be\u6027\u635f\u5931\uff1b(c) \u5176\u4ed6\u5173\u7cfb\u4e2d\u5b50\u5973\u7684\u6700\u4f4e\u57fa\u672c\u751f\u6d3b\u8d39\u7528\u3002"}}]}, {"section_id": "assets_debts", "section_title_en": "Assets and Debts", "fields": [{"field_id": "total_assets", "label_en": "Total Assets", "type": "currency", "required": true, "annotations": {"en": "Total value of all assets. FAM \u00a7 2100 requires full disclosure. Concealing assets is sanctionable under FAM \u00a7 2107.", "es": "Valor total de todos los activos. FAM \u00a7 2100 requiere divulgaci\u00f3n completa. Ocultar activos es sancionable bajo FAM \u00a7 2107.", "zh": "\u6240\u6709\u8d44\u4ea7\u7684\u603b\u4ef7\u503c\u3002FAM \u00a7 2100\u8981\u6c42\u5b8c\u5168\u62ab\u9732\u3002\u6839\u636eFAM \u00a7 2107\uff0c\u9690\u7792\u8d44\u4ea7\u53ef\u53d7\u5904\u7f5a\u3002"}}, {"field_id": "total_debts", "label_en": "Total Debts", "type": "currency", "required": true, "annotations": {"en": "Total of all debts including credit cards, loans, judgments. List creditor, balance, and monthly payment for each.", "es": "Total de todas las deudas incluyendo tarjetas de cr\u00e9dito, pr\u00e9stamos, sentencias.", "zh": "\u6240\u6709\u503a\u52a1\u603b\u989d\uff0c\u5305\u62ec\u4fe1\u7528\u5361\u3001\u8d37\u6b3e\u3001\u5224\u51b3\u3002\u5217\u51fa\u6bcf\u9879\u7684\u503a\u6743\u4eba\u3001\u4f59\u989d\u548c\u6bcf\u6708\u4ed8\u6b3e\u3002"}}]}, {"section_id": "declaration", "fields": [{"field_id": "penalty_of_perjury", "label_en": "Declaration Under Penalty of Perjury", "type": "signature", "required": true, "annotations": {"en": "By signing, you declare under penalty of perjury that the information is true and correct. Perjury is a felony under Penal Code \u00a7 118.", "es": "Al firmar, declara bajo pena de perjurio que la informaci\u00f3n es verdadera y correcta. El perjurio es un delito grave bajo el C\u00f3digo Penal \u00a7 118.", "zh": "\u7b7e\u540d\u5373\u8868\u793a\u60a8\u5728\u4f2a\u8bc1\u5904\u7f5a\u4e0b\u58f0\u660e\u4fe1\u606f\u771f\u5b9e\u51c6\u786e\u3002\u4f2a\u8bc1\u662f\u5211\u6cd5\u7b2c118\u6761\u4e0b\u7684\u91cd\u7f6a\u3002"}}]}], "critical_warnings": {"en": ["Must be current within 3 months of hearing date", "Must attach last 2 months of pay stubs", "All income sources must be disclosed", "Court may impute income if disclosure appears incomplete", "This form is used directly in guideline child support calculations"], "es": ["Debe estar actualizado dentro de 3 meses de la fecha de audiencia", "Debe adjuntar los \u00faltimos 2 meses de recibos de pago", "Todas las fuentes de ingresos deben ser divulgadas", "El tribunal puede imputar ingresos si la divulgaci\u00f3n parece incompleta", "Este formulario se usa directamente en los c\u00e1lculos de manutenci\u00f3n"], "zh": ["\u5fc5\u987b\u5728\u542c\u8bc1\u65e5\u671f\u524d3\u4e2a\u6708\u5185\u66f4\u65b0", "\u5fc5\u987b\u9644\u4e0a\u6700\u8fd12\u4e2a\u6708\u7684\u5de5\u8d44\u5355", "\u5fc5\u987b\u62ab\u9732\u6240\u6709\u6536\u5165\u6765\u6e90", "\u5982\u679c\u62ab\u9732\u770b\u8d77\u6765\u4e0d\u5b8c\u6574\uff0c\u6cd5\u9662\u53ef\u80fd\u63a8\u5b9a\u6536\u5165", "\u6b64\u8868\u683c\u76f4\u63a5\u7528\u4e8e\u6307\u5bfc\u6027\u5b50\u5973\u629a\u517b\u8d39\u8ba1\u7b97"]}, "filing_tips": {"en": ["Use actual numbers from pay stubs, not estimates", "If income varies, average the last 12 months", "Self-employed filers should attach Schedule C from most recent tax return", "Keep a copy for your records"]}}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-300', 'FL-300', 'FL-300', 'A', 'California Courts', 13, '["en","es","zh"]', '{"metadata": {"form_id": "FL-300", "title": "Request for Order", "version": "2.0.0", "created": "2026-02-24", "author": "Michael Vernen Thomas Hartmann", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "governing_statutes": ["FAM \u00a76300", "FAM \u00a73020", "CRC 5.92"], "total_fields": 20}, "fields": [{"field_id": "FL300-01", "label_en": "Attorney or Party Without Attorney", "section": "header", "type": "text", "required": true, "guidance_en": "Full legal name of the requesting party or attorney with State Bar number.", "guidance_es": "Nombre legal completo de la parte solicitante o abogado con n\u00famero del Colegio de Abogados.", "guidance_zh": "\u8bf7\u6c42\u65b9\u6216\u5f8b\u5e08\u7684\u5b8c\u6574\u6cd5\u5b9a\u59d3\u540d\u53ca\u5dde\u5f8b\u5e08\u534f\u4f1a\u7f16\u53f7\u3002", "common_errors": ["Name inconsistency with earlier filings"], "statutory_basis": "CRC 2.111"}, {"field_id": "FL300-02", "label_en": "Court / County / Case Number", "section": "header", "type": "compound", "required": true, "guidance_en": "Must match existing case. FL-300 is a motion within an existing family law case \u2014 it cannot initiate a new case.", "guidance_es": "Debe coincidir con el caso existente. FL-300 es una moci\u00f3n dentro de un caso de derecho familiar existente.", "guidance_zh": "\u5fc5\u987b\u4e0e\u73b0\u6709\u6848\u4ef6\u4e00\u81f4\u3002FL-300\u662f\u73b0\u6709\u5bb6\u5ead\u6cd5\u6848\u4ef6\u4e2d\u7684\u52a8\u8bae\u2014\u2014\u4e0d\u80fd\u7528\u4e8e\u542f\u52a8\u65b0\u6848\u4ef6\u3002", "common_errors": ["Filing in wrong case", "Using FL-300 to initiate proceedings instead of FL-100"], "statutory_basis": "CRC 5.92"}, {"field_id": "FL300-03", "label_en": "Item 1 \u2014 Hearing Date/Time/Department", "section": "body", "type": "compound", "required": true, "subfields": ["Date", "Time", "Department/Room"], "guidance_en": "You must obtain a hearing date from the court BEFORE filing. Contact the clerk''s office or use the court''s online reservation system. The hearing must be at least 16 court days away (CRC 5.92) to allow proper notice to the other party, plus 5 calendar days for mailing.", "guidance_es": "Debe obtener una fecha de audiencia del tribunal ANTES de presentar. La audiencia debe ser al menos 16 d\u00edas h\u00e1biles de distancia (CRC 5.92) para permitir notificaci\u00f3n adecuada.", "guidance_zh": "\u63d0\u4ea4\u524d\u5fc5\u987b\u4ece\u6cd5\u9662\u83b7\u53d6\u542c\u8bc1\u65e5\u671f\u3002\u542c\u8bc1\u65e5\u671f\u5fc5\u987b\u81f3\u5c11\u572816\u4e2a\u6cd5\u9662\u5de5\u4f5c\u65e5\u4e4b\u540e\uff08CRC 5.92\uff09\uff0c\u4ee5\u4fbf\u5411\u5bf9\u65b9\u53d1\u51fa\u9002\u5f53\u901a\u77e5\uff0c\u53e6\u52a05\u4e2a\u65e5\u5386\u65e5\u7528\u4e8e\u90ae\u5bc4\u3002", "common_errors": ["Filing without first reserving hearing date", "Insufficient notice time", "Not accounting for mailing time"], "statutory_basis": "CRC 5.92, CCP \u00a71005"}, {"field_id": "FL300-04", "label_en": "Item 2 \u2014 Requests", "section": "body", "type": "checkbox_group", "required": true, "options": ["Child custody", "Child visitation (parenting time)", "Child support", "Spousal or partner support", "Attorney fees and costs", "Property restraint", "Other (specify)"], "guidance_en": "Check ALL types of orders you are requesting. You may request multiple types in a single FL-300. Each checked item should be supported by facts in your attached declaration (MC-031). Be specific \u2014 vague requests may be denied.", "guidance_es": "Marque TODOS los tipos de \u00f3rdenes que solicita. Cada elemento debe estar respaldado por hechos en su declaraci\u00f3n adjunta (MC-031).", "guidance_zh": "\u52fe\u9009\u60a8\u8bf7\u6c42\u7684\u6240\u6709\u7c7b\u578b\u7684\u547d\u4ee4\u3002\u6bcf\u4e2a\u52fe\u9009\u9879\u5e94\u7531\u60a8\u9644\u4ef6\u58f0\u660e\uff08MC-031\uff09\u4e2d\u7684\u4e8b\u5b9e\u652f\u6301\u3002", "common_errors": ["Not checking all applicable categories", "Requesting orders without supporting declaration", "Being too vague in ''Other'' specification"], "statutory_basis": "CRC 5.92"}, {"field_id": "FL300-05", "label_en": "Item 3 \u2014 Child Custody Details", "section": "body", "type": "compound", "required": false, "guidance_en": "If requesting custody changes, specify the exact orders sought. State current orders (if any), what you want changed, and why. Attach FL-311 for detailed custody/visitation plan. The court applies the ''best interest'' standard (FAM \u00a73011).", "guidance_es": "Si solicita cambios de custodia, especifique las \u00f3rdenes exactas solicitadas. Adjunte FL-311.", "guidance_zh": "\u5982\u8bf7\u6c42\u53d8\u66f4\u76d1\u62a4\u6743\uff0c\u8bf7\u8bf4\u660e\u8981\u6c42\u7684\u5177\u4f53\u547d\u4ee4\u3002\u8bf4\u660e\u73b0\u6709\u547d\u4ee4\uff08\u5982\u6709\uff09\u3001\u5e0c\u671b\u53d8\u66f4\u7684\u5185\u5bb9\u548c\u539f\u56e0\u3002\u9644\u4e0aFL-311\u3002", "common_errors": ["Not specifying exact orders sought", "Failing to show changed circumstances for modification", "Not attaching FL-311"], "statutory_basis": "FAM \u00a73011, FAM \u00a73020, FAM \u00a73087"}, {"field_id": "FL300-06", "label_en": "Item 4 \u2014 Child Visitation Details", "section": "body", "type": "compound", "required": false, "guidance_en": "Specify the visitation/parenting time schedule requested. Be as detailed as possible \u2014 include regular schedule, holidays, school breaks, transportation arrangements. Vague requests like ''reasonable visitation'' give the court too much discretion.", "guidance_es": "Especifique el horario de visitaci\u00f3n solicitado. Sea lo m\u00e1s detallado posible.", "guidance_zh": "\u8bf4\u660e\u8bf7\u6c42\u7684\u63a2\u89c6/\u80b2\u513f\u65f6\u95f4\u5b89\u6392\u3002\u5c3d\u53ef\u80fd\u8be6\u7ec6\u2014\u2014\u5305\u62ec\u5e38\u89c4\u65f6\u95f4\u8868\u3001\u5047\u671f\u3001\u5b66\u6821\u5047\u671f\u3001\u4ea4\u901a\u5b89\u6392\u3002", "common_errors": ["Being too vague", "Not addressing holidays and school breaks", "Not specifying pickup/dropoff logistics"], "statutory_basis": "FAM \u00a73020, FAM \u00a73040"}, {"field_id": "FL300-07", "label_en": "Item 5 \u2014 Child Support Details", "section": "body", "type": "compound", "required": false, "guidance_en": "If requesting child support, specify the amount requested and basis. California uses guideline formula (FAM \u00a74055). Include both parties'' income information. Attach an Income and Expense Declaration (FL-150) \u2014 this is MANDATORY for any support request.", "guidance_es": "Si solicita manutenci\u00f3n de menores, especifique el monto y la base. Adjunte FL-150 \u2014 esto es OBLIGATORIO.", "guidance_zh": "\u5982\u8bf7\u6c42\u5b50\u5973\u629a\u517b\u8d39\uff0c\u8bf7\u8bf4\u660e\u8bf7\u6c42\u91d1\u989d\u548c\u4f9d\u636e\u3002\u9644\u4e0a\u6536\u5165\u548c\u652f\u51fa\u58f0\u660e\uff08FL-150\uff09\u2014\u2014\u8fd9\u5bf9\u4e8e\u4efb\u4f55\u8d61\u517b\u8d39\u8bf7\u6c42\u90fd\u662f\u5f3a\u5236\u6027\u7684\u3002", "common_errors": ["Not attaching FL-150", "Requesting non-guideline amount without justification", "Not including all income sources"], "statutory_basis": "FAM \u00a74050, FAM \u00a74055"}, {"field_id": "FL300-08", "label_en": "Item 6 \u2014 Spousal/Partner Support Details", "section": "body", "type": "compound", "required": false, "guidance_en": "Specify amount and duration of spousal support requested. For temporary support (pendente lite), courts often use the local county formula. For permanent support, courts consider FAM \u00a74320 factors. FL-150 is MANDATORY.", "guidance_es": "Especifique el monto y duraci\u00f3n de la manutenci\u00f3n conyugal solicitada. FL-150 es OBLIGATORIO.", "guidance_zh": "\u8bf4\u660e\u8bf7\u6c42\u7684\u914d\u5076\u8d61\u517b\u8d39\u91d1\u989d\u548c\u671f\u9650\u3002FL-150\u4e3a\u5f3a\u5236\u6027\u9644\u4ef6\u3002", "common_errors": ["Not attaching FL-150", "Not distinguishing temporary from permanent support", "Not addressing FAM \u00a74320 factors in declaration"], "statutory_basis": "FAM \u00a74320, FAM \u00a74330"}, {"field_id": "FL300-09", "label_en": "Item 7 \u2014 Attorney Fees and Costs", "section": "body", "type": "compound", "required": false, "guidance_en": "Request that the other party pay your attorney fees. Court considers income disparity and access to funds (FAM \u00a72030). Also available as a sanction for bad faith conduct (FAM \u00a7271). FL-150 required to show financial need.", "guidance_es": "Solicite que la otra parte pague sus honorarios de abogado. Se requiere FL-150.", "guidance_zh": "\u8bf7\u6c42\u5bf9\u65b9\u652f\u4ed8\u60a8\u7684\u5f8b\u5e08\u8d39\u3002\u6cd5\u9662\u8003\u8651\u6536\u5165\u5dee\u5f02\u548c\u8d44\u91d1\u83b7\u53d6\uff08FAM \u00a72030\uff09\u3002\u9700\u8981FL-150\u3002", "common_errors": ["Not documenting income disparity", "Not filing FL-150", "Not identifying specific sanctionable conduct for \u00a7271 request"], "statutory_basis": "FAM \u00a72030, FAM \u00a7271"}, {"field_id": "FL300-10", "label_en": "Item 8 \u2014 Property Control", "section": "body", "type": "compound", "required": false, "guidance_en": "Request restraining orders regarding property. Can include orders preventing sale, transfer, encumbrance, or concealment of assets beyond the ATROs already in effect from the FL-110.", "guidance_es": "Solicite \u00f3rdenes de restricci\u00f3n sobre propiedad m\u00e1s all\u00e1 de los ATROs.", "guidance_zh": "\u8bf7\u6c42\u5173\u4e8e\u8d22\u4ea7\u7684\u9650\u5236\u4ee4\u3002\u53ef\u5305\u62ec\u7981\u6b62\u51fa\u552e\u3001\u8f6c\u8ba9\u3001\u62b5\u62bc\u6216\u9690\u533f\u8d44\u4ea7\u7684\u547d\u4ee4\u3002", "common_errors": ["Not specifying which property needs protection", "Duplicating ATRO protections unnecessarily"], "statutory_basis": "FAM \u00a72040, FAM \u00a72045"}, {"field_id": "FL300-11", "label_en": "Facts in Support \u2014 Declaration", "section": "body", "type": "attachment_reference", "required": true, "guidance_en": "Every FL-300 MUST be supported by a declaration under penalty of perjury stating the facts justifying the requested orders. Use MC-031 (Attached Declaration) for this. The declaration is the most critical part \u2014 without sufficient facts, the motion will be denied. State facts, not conclusions. Be specific with dates, times, incidents.", "guidance_es": "Todo FL-300 DEBE estar respaldado por una declaraci\u00f3n bajo pena de perjurio. Use MC-031. Sea espec\u00edfico con fechas, horas e incidentes.", "guidance_zh": "\u6bcf\u4efdFL-300\u90fd\u5fc5\u987b\u9644\u6709\u5728\u4f2a\u8bc1\u5904\u7f5a\u6761\u6b3e\u4e0b\u4f5c\u51fa\u7684\u58f0\u660e\u3002\u4f7f\u7528MC-031\u3002\u58f0\u660e\u662f\u6700\u5173\u952e\u7684\u90e8\u5206\u2014\u2014\u6ca1\u6709\u5145\u5206\u7684\u4e8b\u5b9e\uff0c\u52a8\u8bae\u5c06\u88ab\u9a73\u56de\u3002\u9648\u8ff0\u4e8b\u5b9e\u800c\u975e\u7ed3\u8bba\u3002", "common_errors": ["Filing FL-300 without declaration", "Declaration contains conclusions not facts", "Insufficient detail", "Not attaching exhibits to support claims"], "statutory_basis": "CRC 5.92, CCP \u00a72015.5"}, {"field_id": "FL300-12", "label_en": "Signature / Date", "section": "signature", "type": "signature_block", "required": true, "guidance_en": "Sign and date under penalty of perjury.", "guidance_es": "Firme y feche bajo pena de perjurio.", "guidance_zh": "\u5728\u4f2a\u8bc1\u5904\u7f5a\u6761\u6b3e\u4e0b\u7b7e\u540d\u5e76\u6ce8\u660e\u65e5\u671f\u3002", "common_errors": ["Unsigned form", "Date inconsistency"], "statutory_basis": "CCP \u00a72015.5"}, {"field_id": "FL300-13", "label_en": "Service Requirements", "section": "procedural", "type": "informational", "required": false, "guidance_en": "The FL-300, supporting declaration, and all attachments must be personally served on the other party at least 16 court days before the hearing, plus 5 calendar days if served by mail (CCP \u00a71005). Use a Proof of Service (FL-330) to document service. Failure to properly serve = hearing may be continued or request denied.", "guidance_es": "El FL-300 debe ser notificado personalmente al menos 16 d\u00edas h\u00e1biles antes de la audiencia, m\u00e1s 5 d\u00edas calendario si se notifica por correo.", "guidance_zh": "FL-300\u5fc5\u987b\u5728\u542c\u8bc1\u65e5\u81f3\u5c1116\u4e2a\u6cd5\u9662\u5de5\u4f5c\u65e5\u524d\u4eb2\u81ea\u9001\u8fbe\u5bf9\u65b9\uff0c\u5982\u901a\u8fc7\u90ae\u5bc4\u9001\u8fbe\u5219\u53e6\u52a05\u4e2a\u65e5\u5386\u65e5\u3002", "common_errors": ["Insufficient notice period", "Not serving all attachments", "No proof of service filed", "Serving by mail without adding 5 days"], "statutory_basis": "CCP \u00a71005, CRC 5.92"}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-305', 'FL-305', 'FL-305', 'A', 'California Courts', 9, '["en","es","zh"]', '{"metadata": {"form_id": "FL-305", "title": "Temporary Emergency (Ex Parte) Orders", "version": "2.0.0", "created": "2026-02-24", "author": "Michael Vernen Thomas Hartmann", "copyright": "\u00a9 2024\u20132026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "governing_statutes": ["FAM \u00a76340", "CRC 5.151", "CRC 5.165"], "total_fields": 15}, "fields": [{"field_id": "FL305-01", "label_en": "Header / Party Information", "section": "header", "type": "compound", "required": true, "guidance_en": "Standard header \u2014 must match existing case. FL-305 is filed alongside FL-300 and a supporting declaration when emergency orders are needed before the regular hearing date.", "guidance_es": "Encabezado est\u00e1ndar \u2014 debe coincidir con el caso existente. FL-305 se presenta junto con FL-300 y una declaraci\u00f3n de apoyo.", "guidance_zh": "\u6807\u51c6\u8868\u5934\u2014\u2014\u5fc5\u987b\u4e0e\u73b0\u6709\u6848\u4ef6\u4e00\u81f4\u3002FL-305\u4e0eFL-300\u53ca\u652f\u6301\u58f0\u660e\u4e00\u540c\u63d0\u4ea4\u3002", "common_errors": ["Filing FL-305 without FL-300", "Party name inconsistency"], "statutory_basis": "CRC 5.151"}, {"field_id": "FL305-02", "label_en": "Item 1 \u2014 Immediate Danger / Irreparable Harm", "section": "body", "type": "text_area", "required": true, "guidance_en": "You MUST demonstrate IMMEDIATE DANGER to a person or IRREPARABLE HARM to property that cannot wait for a regular hearing. This is the threshold test. General inconvenience or disagreements are NOT sufficient. Examples of qualifying emergencies: child abduction risk, domestic violence, imminent property destruction or dissipation, unauthorized removal of children from jurisdiction.", "guidance_es": "DEBE demostrar PELIGRO INMEDIATO a una persona o DA\u00d1O IRREPARABLE a la propiedad que no puede esperar. La incomodidad general NO es suficiente.", "guidance_zh": "\u60a8\u5fc5\u987b\u8bc1\u660e\u5bf9\u4eba\u8eab\u7684\u5373\u65f6\u5371\u9669\u6216\u5bf9\u8d22\u4ea7\u7684\u4e0d\u53ef\u633d\u56de\u7684\u635f\u5bb3\uff0c\u65e0\u6cd5\u7b49\u5f85\u5e38\u89c4\u542c\u8bc1\u3002\u4e00\u822c\u4e0d\u4fbf\u6216\u5206\u6b67\u4e0d\u8db3\u4ee5\u6ee1\u8db3\u6761\u4ef6\u3002", "common_errors": ["Not meeting the emergency threshold", "Filing ex parte for non-emergency issues", "Insufficient factual showing of immediate harm", "Using ex parte as tactical tool rather than genuine emergency"], "statutory_basis": "CRC 5.151(b), FAM \u00a76340"}, {"field_id": "FL305-03", "label_en": "Item 2 \u2014 Notice to Other Party", "section": "body", "type": "checkbox_group", "required": true, "options": ["Personal notice was given", "Notice was given by telephone", "Notice was given by fax/email", "Notice was given by other means (specify)", "Notice was attempted but could not be given because", "Notice should not be required because"], "guidance_en": "You MUST give notice to the other party before filing an ex parte motion (CRC 5.165). Notice must be given by 10:00 AM the court day before the ex parte hearing. If notice was not possible, you must explain why. The court may deny the request if proper notice was not attempted.", "guidance_es": "DEBE notificar a la otra parte antes de presentar una moci\u00f3n ex parte (CRC 5.165). La notificaci\u00f3n debe darse antes de las 10:00 AM del d\u00eda h\u00e1bil anterior.", "guidance_zh": "\u5728\u63d0\u4ea4\u7d27\u6025\u52a8\u8bae\u524d\uff0c\u60a8\u5fc5\u987b\u901a\u77e5\u5bf9\u65b9\uff08CRC 5.165\uff09\u3002\u901a\u77e5\u5fc5\u987b\u5728\u7d27\u6025\u542c\u8bc1\u524d\u4e00\u4e2a\u6cd5\u9662\u5de5\u4f5c\u65e5\u4e0a\u534810:00\u524d\u53d1\u51fa\u3002", "common_errors": ["Not giving required notice", "Notice given too late", "Not documenting notice attempts", "Not explaining why notice couldn''t be given"], "statutory_basis": "CRC 5.165"}, {"field_id": "FL305-04", "label_en": "Item 3 \u2014 Temporary Emergency Orders Requested", "section": "body", "type": "checkbox_group", "required": true, "options": ["Temporary custody order", "Temporary visitation order", "No removal of children from state", "Child abduction prevention", "Property restraining orders", "Exclusive use of dwelling", "Stay-away order", "Other (specify)"], "guidance_en": "Check ALL emergency orders requested. Each must be supported by specific facts in the declaration showing why it cannot wait. Temporary orders remain in effect until the regular hearing date unless modified by the court.", "guidance_es": "Marque TODAS las \u00f3rdenes de emergencia solicitadas. Cada una debe estar respaldada por hechos espec\u00edficos.", "guidance_zh": "\u52fe\u9009\u6240\u6709\u8bf7\u6c42\u7684\u7d27\u6025\u547d\u4ee4\u3002\u6bcf\u9879\u90fd\u5fc5\u987b\u7531\u58f0\u660e\u4e2d\u7684\u5177\u4f53\u4e8b\u5b9e\u652f\u6301\u3002", "common_errors": ["Requesting orders not supported by emergency facts", "Not being specific about what orders are needed"], "statutory_basis": "CRC 5.151, FAM \u00a76340"}, {"field_id": "FL305-05", "label_en": "Item 4 \u2014 Child Custody Emergency", "section": "body", "type": "text_area", "required": false, "guidance_en": "If requesting emergency custody, describe the specific risk to the child. Courts require showing of ''immediate harm'' or ''irreparable harm'' \u2014 not just that a different custody arrangement would be better. Include dates, specific incidents, and any police reports or CPS involvement.", "guidance_es": "Si solicita custodia de emergencia, describa el riesgo espec\u00edfico para el ni\u00f1o. Se requiere demostrar ''da\u00f1o inmediato'' o ''da\u00f1o irreparable.''", "guidance_zh": "\u5982\u8bf7\u6c42\u7d27\u6025\u76d1\u62a4\u6743\uff0c\u8bf7\u63cf\u8ff0\u5bf9\u513f\u7ae5\u7684\u5177\u4f53\u98ce\u9669\u3002\u6cd5\u9662\u8981\u6c42\u8bc1\u660e''\u5373\u65f6\u4f24\u5bb3''\u6216''\u4e0d\u53ef\u633d\u56de\u7684\u4f24\u5bb3''\u3002", "common_errors": ["Conclusory allegations without specific facts", "Not including supporting evidence", "Exaggerating or fabricating emergency to gain tactical advantage"], "statutory_basis": "FAM \u00a73064"}, {"field_id": "FL305-06", "label_en": "Item 5 \u2014 Property Emergency", "section": "body", "type": "text_area", "required": false, "guidance_en": "If requesting emergency property orders, describe the specific risk of dissipation, destruction, or concealment. Include evidence of recent or imminent transfers, withdrawals, or destruction.", "guidance_es": "Si solicita \u00f3rdenes de propiedad de emergencia, describa el riesgo espec\u00edfico de disipaci\u00f3n, destrucci\u00f3n u ocultamiento.", "guidance_zh": "\u5982\u8bf7\u6c42\u7d27\u6025\u8d22\u4ea7\u547d\u4ee4\uff0c\u8bf7\u63cf\u8ff0\u8d44\u4ea7\u88ab\u8f6c\u79fb\u3001\u9500\u6bc1\u6216\u9690\u533f\u7684\u5177\u4f53\u98ce\u9669\u3002", "common_errors": ["Not showing imminent risk \u2014 past transfers alone may not qualify", "Not specifying which assets are at risk"], "statutory_basis": "FAM \u00a72045"}, {"field_id": "FL305-07", "label_en": "Declaration in Support", "section": "body", "type": "attachment_reference", "required": true, "guidance_en": "A detailed declaration (MC-031) MUST accompany this form. The declaration must: (1) state facts showing immediate danger or irreparable harm, (2) explain why relief cannot wait for regular hearing, (3) describe all notice attempts, (4) include any supporting evidence as exhibits. This is the make-or-break document \u2014 without a strong declaration, the ex parte will be denied.", "guidance_es": "Una declaraci\u00f3n detallada (MC-031) DEBE acompa\u00f1ar este formulario. Es el documento determinante.", "guidance_zh": "\u8be6\u7ec6\u58f0\u660e\uff08MC-031\uff09\u5fc5\u987b\u968f\u9644\u672c\u8868\u683c\u3002\u58f0\u660e\u5fc5\u987b\uff1a(1)\u9648\u8ff0\u8bc1\u660e\u5373\u65f6\u5371\u9669\u7684\u4e8b\u5b9e\uff0c(2)\u89e3\u91ca\u4e3a\u4f55\u4e0d\u80fd\u7b49\u5f85\u5e38\u89c4\u542c\u8bc1\uff0c(3)\u63cf\u8ff0\u6240\u6709\u901a\u77e5\u5c1d\u8bd5\uff0c(4)\u9644\u4e0a\u652f\u6301\u8bc1\u636e\u3002", "common_errors": ["Declaration too conclusory", "No supporting exhibits", "Not explaining urgency adequately", "Declaration contradicts FL-305 checkboxes"], "statutory_basis": "CRC 5.151, CCP \u00a72015.5"}, {"field_id": "FL305-08", "label_en": "Signature / Date", "section": "signature", "type": "signature_block", "required": true, "guidance_en": "Sign under penalty of perjury with date, city, and state.", "guidance_es": "Firme bajo pena de perjurio con fecha, ciudad y estado.", "guidance_zh": "\u5728\u4f2a\u8bc1\u5904\u7f5a\u6761\u6b3e\u4e0b\u7b7e\u540d\uff0c\u6ce8\u660e\u65e5\u671f\u3001\u57ce\u5e02\u548c\u5dde\u3002", "common_errors": ["Unsigned", "Date inconsistent with filing date"], "statutory_basis": "CCP \u00a72015.5"}, {"field_id": "FL305-09", "label_en": "Procedural Requirements", "section": "procedural", "type": "informational", "required": false, "guidance_en": "Ex parte procedure: (1) Reserve ex parte hearing slot with clerk, (2) Give notice to other party by 10 AM day before hearing (CRC 5.165), (3) File FL-300 + FL-305 + declaration + proof of notice attempt, (4) Appear at hearing. The other party has the right to appear and oppose. If granted, orders are temporary until the regular hearing date on the FL-300.", "guidance_es": "Procedimiento ex parte: (1) Reserve audiencia, (2) Notifique para las 10 AM del d\u00eda anterior, (3) Presente FL-300 + FL-305 + declaraci\u00f3n, (4) Comparezca.", "guidance_zh": "\u7d27\u6025\u7a0b\u5e8f\uff1a(1)\u5411\u4e66\u8bb0\u5458\u9884\u7ea6\u7d27\u6025\u542c\u8bc1\uff0c(2)\u5728\u542c\u8bc1\u524d\u4e00\u5929\u4e0a\u534810\u70b9\u524d\u901a\u77e5\u5bf9\u65b9\uff0c(3)\u63d0\u4ea4FL-300 + FL-305 +\u58f0\u660e+\u901a\u77e5\u8bc1\u660e\uff0c(4)\u51fa\u5ead\u3002", "common_errors": ["Not reserving hearing slot", "Missing notice deadline", "Not filing all required documents together", "Not appearing at hearing"], "statutory_basis": "CRC 5.151, CRC 5.165"}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-311', 'FL-311', 'FL-311', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "FL-311", "form_title": "Child Custody and Visitation (Parenting Time) Application Attachment", "statutory_authority": "Family Code \u00a7\u00a7 3020-3048, 3080-3089; CRC Rule 5.210", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "legal_custody", "fields": [{"field_id": "fl311_legal_custody", "field_label": "Legal custody request", "field_type": "radio", "required": true, "guidance": {"en": "Legal custody means the right to make major decisions about your child''s health, education, and welfare. Choose: Joint (both parents decide together) or Sole (one parent decides alone).", "es": "La custodia legal significa el derecho a tomar decisiones importantes sobre la salud, educaci\u00f3n y bienestar de su hijo.", "zh": "Legal custody means the right to make major decisions about your child''s health, education, and welfare.", "vi": "Legal custody means the right to make major decisions about your child''s health, education, and welfare.", "so": "Legal custody means the right to make major decisions.", "ti": "Legal custody means the right to make major decisions.", "am": "Legal custody means the right to make major decisions.", "ar": "Legal custody means the right to make major decisions.", "ht": "Legal custody means the right to make major decisions.", "ko": "Legal custody means the right to make major decisions.", "pt": "Legal custody means the right to make major decisions.", "ru": "Legal custody means the right to make major decisions.", "tl": "Legal custody means the right to make major decisions."}, "legal_reference": "Family Code \u00a7\u00a7 3003, 3080", "common_errors": {}, "tips": {}}, {"field_id": "fl311_legal_custody_to", "field_label": "Legal custody to", "field_type": "text", "required": true, "guidance": {"en": "If requesting sole legal custody, state which parent. If joint, leave blank or write ''Both parents''.", "es": "Si solicita custodia legal exclusiva, indique cu\u00e1l padre.", "zh": "If requesting sole legal custody, state which parent.", "vi": "If requesting sole legal custody, state which parent.", "so": "State which parent for sole custody.", "ti": "State which parent for sole custody.", "am": "State which parent for sole custody.", "ar": "State which parent for sole custody.", "ht": "State which parent for sole custody.", "ko": "State which parent for sole custody.", "pt": "State which parent for sole custody.", "ru": "State which parent for sole custody.", "tl": "State which parent for sole custody."}, "legal_reference": "Family Code \u00a7 3006", "common_errors": {}, "tips": {}}]}, {"section_id": "physical_custody", "fields": [{"field_id": "fl311_physical_custody", "field_label": "Physical custody request", "field_type": "radio", "required": true, "guidance": {"en": "Physical custody means where the child lives. Joint physical custody means substantial time with both parents. Sole physical custody means the child lives primarily with one parent.", "es": "La custodia f\u00edsica significa d\u00f3nde vive el ni\u00f1o.", "zh": "Physical custody means where the child lives.", "vi": "Physical custody means where the child lives.", "so": "Physical custody means where the child lives.", "ti": "Physical custody means where the child lives.", "am": "Physical custody means where the child lives.", "ar": "Physical custody means where the child lives.", "ht": "Physical custody means where the child lives.", "ko": "Physical custody means where the child lives.", "pt": "Physical custody means where the child lives.", "ru": "Physical custody means where the child lives.", "tl": "Physical custody means where the child lives."}, "legal_reference": "Family Code \u00a7\u00a7 3004, 3007, 3081", "common_errors": {}, "tips": {}}, {"field_id": "fl311_physical_custody_to", "field_label": "Physical custody to", "field_type": "text", "required": true, "guidance": {"en": "State which parent should have primary physical custody or if requesting joint physical custody.", "es": "Indique cu\u00e1l padre debe tener la custodia f\u00edsica principal.", "zh": "State which parent should have primary physical custody.", "vi": "State which parent should have primary physical custody.", "so": "State which parent for primary physical custody.", "ti": "State which parent for primary physical custody.", "am": "State which parent for primary physical custody.", "ar": "State which parent for primary physical custody.", "ht": "State which parent for primary physical custody.", "ko": "State which parent for primary physical custody.", "pt": "State which parent for primary physical custody.", "ru": "State which parent for primary physical custody.", "tl": "State which parent for primary physical custody."}, "legal_reference": "", "common_errors": {}, "tips": {}}]}, {"section_id": "visitation_schedule", "fields": [{"field_id": "fl311_visitation_type", "field_label": "Visitation schedule type", "field_type": "radio", "required": true, "guidance": {"en": "Choose the type of visitation schedule: reasonable visitation (flexible, parents agree), specific schedule (detailed days/times), or supervised visitation (third party present).", "es": "Elija el tipo de horario de visitaci\u00f3n.", "zh": "Choose visitation type: reasonable, specific schedule, or supervised.", "vi": "Choose visitation type: reasonable, specific schedule, or supervised.", "so": "Choose visitation type.", "ti": "Choose visitation type.", "am": "Choose visitation type.", "ar": "Choose visitation type.", "ht": "Choose visitation type.", "ko": "Choose visitation type.", "pt": "Choose visitation type.", "ru": "Choose visitation type.", "tl": "Choose visitation type."}, "legal_reference": "Family Code \u00a7\u00a7 3100-3105", "common_errors": {}, "tips": {}}, {"field_id": "fl311_visitation_details", "field_label": "Visitation schedule details", "field_type": "textarea", "required": true, "guidance": {"en": "Describe the specific visitation schedule you are requesting. Include: regular schedule (weekdays/weekends), holiday schedule, summer/vacation schedule, and any special conditions.", "es": "Describa el horario de visitaci\u00f3n espec\u00edfico que solicita.", "zh": "Describe the specific visitation schedule including regular, holiday, and summer schedules.", "vi": "Describe the specific visitation schedule.", "so": "Describe the visitation schedule.", "ti": "Describe the visitation schedule.", "am": "Describe the visitation schedule.", "ar": "Describe the visitation schedule.", "ht": "Describe the visitation schedule.", "ko": "Describe the visitation schedule.", "pt": "Describe the visitation schedule.", "ru": "Describe the visitation schedule.", "tl": "Describe the visitation schedule."}, "legal_reference": "CRC Rule 5.210(e)", "common_errors": {"en": "Being too vague. Courts prefer specific, enforceable schedules with exact days and times.", "es": "Being too vague.", "zh": "Being too vague.", "vi": "Being too vague.", "so": "Being too vague.", "ti": "Being too vague.", "am": "Being too vague.", "ar": "Being too vague.", "ht": "Being too vague.", "ko": "Being too vague.", "pt": "Being too vague.", "ru": "Being too vague.", "tl": "Being too vague."}, "tips": {"en": "Include pickup/dropoff times and locations. Address holidays by name and year (alternating).", "es": "Include pickup/dropoff times and locations.", "zh": "Include pickup/dropoff times and locations.", "vi": "Include pickup/dropoff times and locations.", "so": "Include pickup/dropoff details.", "ti": "Include pickup/dropoff details.", "am": "Include pickup/dropoff details.", "ar": "Include pickup/dropoff details.", "ht": "Include pickup/dropoff details.", "ko": "Include pickup/dropoff details.", "pt": "Include pickup/dropoff details.", "ru": "Include pickup/dropoff details.", "tl": "Include pickup/dropoff details."}}]}, {"section_id": "best_interest_factors", "fields": [{"field_id": "fl311_best_interest", "field_label": "Facts supporting best interest of child", "field_type": "textarea", "required": true, "guidance": {"en": "Explain why your requested custody arrangement serves the child''s best interest. Address: child''s health and safety, child''s relationship with each parent, history of abuse or domestic violence, child''s ties to school and community.", "es": "Explique por qu\u00e9 su acuerdo de custodia solicitado sirve al mejor inter\u00e9s del ni\u00f1o.", "zh": "Explain why your custody arrangement serves the child''s best interest.", "vi": "Explain why your custody arrangement serves the child''s best interest.", "so": "Explain best interest factors.", "ti": "Explain best interest factors.", "am": "Explain best interest factors.", "ar": "Explain best interest factors.", "ht": "Explain best interest factors.", "ko": "Explain best interest factors.", "pt": "Explain best interest factors.", "ru": "Explain best interest factors.", "tl": "Explain best interest factors."}, "legal_reference": "Family Code \u00a7\u00a7 3011, 3020, 3040, 3044", "common_errors": {"en": "Focusing on what''s wrong with the other parent instead of what''s best for the child.", "es": "Focusing on the other parent instead of the child.", "zh": "Focusing on the other parent instead of the child.", "vi": "Focusing on the other parent instead of the child.", "so": "Focus on the child, not the other parent.", "ti": "Focus on the child, not the other parent.", "am": "Focus on the child, not the other parent.", "ar": "Focus on the child, not the other parent.", "ht": "Focus on the child, not the other parent.", "ko": "Focus on the child, not the other parent.", "pt": "Focus on the child, not the other parent.", "ru": "Focus on the child, not the other parent.", "tl": "Focus on the child, not the other parent."}, "tips": {"en": "Courts focus on the child''s needs, not parental conflict. Lead with the child''s wellbeing.", "es": "Courts focus on the child''s needs.", "zh": "Courts focus on the child''s needs.", "vi": "Courts focus on the child''s needs.", "so": "Lead with the child''s wellbeing.", "ti": "Lead with the child''s wellbeing.", "am": "Lead with the child''s wellbeing.", "ar": "Lead with the child''s wellbeing.", "ht": "Lead with the child''s wellbeing.", "ko": "Lead with the child''s wellbeing.", "pt": "Lead with the child''s wellbeing.", "ru": "Lead with the child''s wellbeing.", "tl": "Lead with the child''s wellbeing."}}]}, {"section_id": "dv_allegations", "fields": [{"field_id": "fl311_dv_history", "field_label": "History of domestic violence (if applicable)", "field_type": "textarea", "required": false, "guidance": {"en": "If there is a history of domestic violence, describe incidents with dates and details. Under Family Code \u00a7 3044, there is a rebuttable presumption against custody to a parent who committed DV within the last 5 years.", "es": "Si hay un historial de violencia dom\u00e9stica, describa los incidentes con fechas y detalles.", "zh": "Describe DV history with dates. FC \u00a7 3044 creates presumption against custody for DV perpetrator.", "vi": "Describe DV history with dates. FC \u00a7 3044 creates presumption against custody for DV perpetrator.", "so": "Describe DV history with dates and details.", "ti": "Describe DV history with dates and details.", "am": "Describe DV history with dates and details.", "ar": "Describe DV history with dates and details.", "ht": "Describe DV history with dates and details.", "ko": "Describe DV history with dates and details.", "pt": "Describe DV history with dates and details.", "ru": "Describe DV history with dates and details.", "tl": "Describe DV history with dates and details."}, "legal_reference": "Family Code \u00a7\u00a7 3044, 3011(b)(5)", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-312', 'FL-312', 'FL-312', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "FL-312", "form_title": "Child Abduction Prevention Order Attachment", "statutory_authority": "Family Code \u00a7\u00a7 3040-3048, 3130-3134; Penal Code \u00a7 278.5", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "risk_factors", "fields": [{"field_id": "fl312_risk_factors", "field_label": "Risk factors for abduction", "field_type": "checkbox", "required": true, "guidance": {"en": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "es": "Marque todos los factores que aplican.", "zh": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "vi": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "so": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "ti": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "am": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "ar": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "ht": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "ko": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "pt": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "ru": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns.", "tl": "Check all factors that apply: prior threats to take child, prior actual abduction, no strong ties to community, recent sale of property, quitting job, closing bank accounts, obtaining passport/travel documents, domestic violence history, substance abuse, mental health concerns."}, "legal_reference": "Family Code \u00a7 3048(b)", "common_errors": {}, "tips": {}}, {"field_id": "fl312_specific_facts", "field_label": "Specific facts supporting risk", "field_type": "textarea", "required": true, "guidance": {"en": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "es": "Describa incidentes espec\u00edficos que demuestren el riesgo de secuestro.", "zh": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "vi": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "so": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "ti": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "am": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "ar": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "ht": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "ko": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "pt": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "ru": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation.", "tl": "Describe specific incidents, statements, or actions that demonstrate a risk of child abduction. Include dates, witnesses, and any documentation."}, "legal_reference": "Family Code \u00a7 3048(b)(1)-(2)", "common_errors": {}, "tips": {}}]}, {"section_id": "prevention_orders", "fields": [{"field_id": "fl312_orders_requested", "field_label": "Orders requested", "field_type": "checkbox", "required": true, "guidance": {"en": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "es": "Marque todas las \u00f3rdenes de prevenci\u00f3n que solicita.", "zh": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "vi": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "so": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "ti": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "am": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "ar": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "ht": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "ko": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "pt": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "ru": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy.", "tl": "Check all prevention orders you are requesting: surrender passport, no removal from state/county/country, supervised visitation only, posting bond, registering custody order with consulate/embassy."}, "legal_reference": "Family Code \u00a7 3048(a)", "common_errors": {}, "tips": {}}, {"field_id": "fl312_travel_restrictions", "field_label": "Travel restrictions", "field_type": "textarea", "required": true, "guidance": {"en": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "es": "Especifique qu\u00e9 restricciones de viaje desea.", "zh": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "vi": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "so": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "ti": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "am": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "ar": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "ht": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "ko": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "pt": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "ru": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''", "tl": "Specify what travel restrictions you want. Example: ''Respondent shall not remove the child from California without prior written consent of Petitioner or court order.''"}, "legal_reference": "Family Code \u00a7\u00a7 3048(a)(1), 3131", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fl-320', 'FL-320', 'FL-320', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "FL-320", "form_title": "Responsive Declaration to Request for Order", "statutory_authority": "CRC Rule 5.92; Family Code \u00a7 217", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "header_info", "fields": [{"field_id": "fl320_your_name", "field_label": "Your name (responding party)", "field_type": "text", "required": true, "guidance": {"en": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "es": "Ingrese su nombre legal completo. Usted es la persona que responde a la moci\u00f3n.", "zh": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "vi": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "so": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "ti": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "am": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "ar": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "ht": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "ko": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "pt": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "ru": "Enter your full legal name. You are the person responding to the motion filed by the other party.", "tl": "Enter your full legal name. You are the person responding to the motion filed by the other party."}, "legal_reference": "CRC Rule 5.92", "common_errors": {}, "tips": {}}, {"field_id": "fl320_other_party", "field_label": "Other party''s name", "field_type": "text", "required": true, "guidance": {"en": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "es": "Ingrese el nombre legal completo de la persona que present\u00f3 la Solicitud de Orden.", "zh": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "vi": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "so": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "ti": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "am": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "ar": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "ht": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "ko": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "pt": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "ru": "Enter the full legal name of the person who filed the Request for Order (FL-300).", "tl": "Enter the full legal name of the person who filed the Request for Order (FL-300)."}, "legal_reference": "", "common_errors": {}, "tips": {}}, {"field_id": "fl320_case_number", "field_label": "Case number", "field_type": "text", "required": true, "guidance": {"en": "Enter the case number from your existing case. This appears on all previously filed documents.", "es": "Ingrese el n\u00famero de caso de su caso existente.", "zh": "Enter the case number from your existing case.", "vi": "Enter the case number from your existing case.", "so": "Enter the case number from your existing case.", "ti": "Enter the case number from your existing case.", "am": "Enter the case number from your existing case.", "ar": "Enter the case number from your existing case.", "ht": "Enter the case number from your existing case.", "ko": "Enter the case number from your existing case.", "pt": "Enter the case number from your existing case.", "ru": "Enter the case number from your existing case.", "tl": "Enter the case number from your existing case."}, "legal_reference": "", "common_errors": {}, "tips": {}}]}, {"section_id": "response_to_requests", "fields": [{"field_id": "fl320_agree_disagree", "field_label": "Do you agree or disagree with the requests?", "field_type": "checkbox", "required": true, "guidance": {"en": "Check the boxes indicating which requests you agree with and which you oppose. You must state specific facts supporting your position.", "es": "Marque las casillas indicando con cu\u00e1les solicitudes est\u00e1 de acuerdo y cu\u00e1les se opone.", "zh": "Check the boxes indicating which requests you agree with and which you oppose.", "vi": "Check the boxes indicating which requests you agree with and which you oppose.", "so": "Check the boxes indicating which requests you agree with and which you oppose.", "ti": "Check the boxes indicating which requests you agree with and which you oppose.", "am": "Check the boxes indicating which requests you agree with and which you oppose.", "ar": "Check the boxes indicating which requests you agree with and which you oppose.", "ht": "Check the boxes indicating which requests you agree with and which you oppose.", "ko": "Check the boxes indicating which requests you agree with and which you oppose.", "pt": "Check the boxes indicating which requests you agree with and which you oppose.", "ru": "Check the boxes indicating which requests you agree with and which you oppose.", "tl": "Check the boxes indicating which requests you agree with and which you oppose."}, "legal_reference": "Family Code \u00a7 217", "common_errors": {}, "tips": {}}, {"field_id": "fl320_facts", "field_label": "Facts supporting your response", "field_type": "textarea", "required": true, "guidance": {"en": "State specific facts that support your position. Include dates, names, and details. Avoid opinions \u2014 courts rely on facts.", "es": "Indique hechos espec\u00edficos que respalden su posici\u00f3n. Incluya fechas, nombres y detalles.", "zh": "State specific facts that support your position. Include dates, names, and details.", "vi": "State specific facts that support your position. Include dates, names, and details.", "so": "State specific facts that support your position. Include dates, names, and details.", "ti": "State specific facts that support your position. Include dates, names, and details.", "am": "State specific facts that support your position. Include dates, names, and details.", "ar": "State specific facts that support your position. Include dates, names, and details.", "ht": "State specific facts that support your position. Include dates, names, and details.", "ko": "State specific facts that support your position. Include dates, names, and details.", "pt": "State specific facts that support your position. Include dates, names, and details.", "ru": "State specific facts that support your position. Include dates, names, and details.", "tl": "State specific facts that support your position. Include dates, names, and details."}, "legal_reference": "Family Code \u00a7 217; Evidence Code \u00a7 702", "common_errors": {"en": "Stating opinions without supporting facts. The court needs evidence, not feelings.", "es": "Stating opinions without supporting facts.", "zh": "Stating opinions without supporting facts.", "vi": "Stating opinions without supporting facts.", "so": "Stating opinions without supporting facts.", "ti": "Stating opinions without supporting facts.", "am": "Stating opinions without supporting facts.", "ar": "Stating opinions without supporting facts.", "ht": "Stating opinions without supporting facts.", "ko": "Stating opinions without supporting facts.", "pt": "Stating opinions without supporting facts.", "ru": "Stating opinions without supporting facts.", "tl": "Stating opinions without supporting facts."}, "tips": {"en": "Organize by topic. Address each request made by the other party separately.", "es": "Organize by topic.", "zh": "Organize by topic.", "vi": "Organize by topic.", "so": "Organize by topic.", "ti": "Organize by topic.", "am": "Organize by topic.", "ar": "Organize by topic.", "ht": "Organize by topic.", "ko": "Organize by topic.", "pt": "Organize by topic.", "ru": "Organize by topic.", "tl": "Organize by topic."}}]}, {"section_id": "custody_visitation", "fields": [{"field_id": "fl320_custody_response", "field_label": "Response to custody/visitation request", "field_type": "textarea", "required": false, "guidance": {"en": "If the other party requested changes to custody or visitation, explain your position and what arrangement serves the child''s best interest.", "es": "Si la otra parte solicit\u00f3 cambios en la custodia o visitaci\u00f3n, explique su posici\u00f3n.", "zh": "If the other party requested changes to custody or visitation, explain your position.", "vi": "If the other party requested changes to custody or visitation, explain your position.", "so": "If the other party requested changes to custody or visitation, explain your position.", "ti": "If the other party requested changes to custody or visitation, explain your position.", "am": "If the other party requested changes to custody or visitation, explain your position.", "ar": "If the other party requested changes to custody or visitation, explain your position.", "ht": "If the other party requested changes to custody or visitation, explain your position.", "ko": "If the other party requested changes to custody or visitation, explain your position.", "pt": "If the other party requested changes to custody or visitation, explain your position.", "ru": "If the other party requested changes to custody or visitation, explain your position.", "tl": "If the other party requested changes to custody or visitation, explain your position."}, "legal_reference": "Family Code \u00a7\u00a7 3011, 3020, 3040", "common_errors": {}, "tips": {}}]}, {"section_id": "support_response", "fields": [{"field_id": "fl320_support_response", "field_label": "Response to support request", "field_type": "textarea", "required": false, "guidance": {"en": "If the other party requested child or spousal support changes, state your position on the amount and provide income information.", "es": "Si la otra parte solicit\u00f3 cambios en la manutenci\u00f3n, indique su posici\u00f3n sobre el monto.", "zh": "If the other party requested support changes, state your position.", "vi": "If the other party requested support changes, state your position.", "so": "If the other party requested support changes, state your position.", "ti": "If the other party requested support changes, state your position.", "am": "If the other party requested support changes, state your position.", "ar": "If the other party requested support changes, state your position.", "ht": "If the other party requested support changes, state your position.", "ko": "If the other party requested support changes, state your position.", "pt": "If the other party requested support changes, state your position.", "ru": "If the other party requested support changes, state your position.", "tl": "If the other party requested support changes, state your position."}, "legal_reference": "Family Code \u00a7\u00a7 3620-3634, 4320", "common_errors": {}, "tips": {}}]}, {"section_id": "declaration", "fields": [{"field_id": "fl320_declaration", "field_label": "Declaration under penalty of perjury", "field_type": "textarea", "required": true, "guidance": {"en": "This is your sworn statement. Everything you write here must be true and based on your personal knowledge. False statements are punishable as perjury under Penal Code \u00a7 118.", "es": "Esta es su declaraci\u00f3n jurada. Todo lo que escriba aqu\u00ed debe ser verdadero.", "zh": "This is your sworn statement. Everything must be true and based on personal knowledge.", "vi": "This is your sworn statement. Everything must be true and based on personal knowledge.", "so": "This is your sworn statement. Everything must be true and based on personal knowledge.", "ti": "This is your sworn statement. Everything must be true and based on personal knowledge.", "am": "This is your sworn statement. Everything must be true and based on personal knowledge.", "ar": "This is your sworn statement. Everything must be true and based on personal knowledge.", "ht": "This is your sworn statement. Everything must be true and based on personal knowledge.", "ko": "This is your sworn statement. Everything must be true and based on personal knowledge.", "pt": "This is your sworn statement. Everything must be true and based on personal knowledge.", "ru": "This is your sworn statement. Everything must be true and based on personal knowledge.", "tl": "This is your sworn statement. Everything must be true and based on personal knowledge."}, "legal_reference": "CCP \u00a7 2015.5; Penal Code \u00a7 118", "common_errors": {}, "tips": {}}]}]}');
