INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fw-001', 'FW-001', 'FW-001', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "FW-001", "form_title": "Request to Waive Court Fees", "statutory_authority": "Government Code \u00a7\u00a7 68630-68641", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "basis_for_waiver", "fields": [{"field_id": "fw001_basis", "field_label": "Basis for fee waiver request", "field_type": "radio", "required": true, "guidance": {"en": "Choose one: (a) You receive public benefits (Medi-Cal, Food Stamps/CalFresh, SSI, SSP, CAPI, CalWORKs, Tribal TANF, IHSS); (b) Your household income is at or below the poverty guidelines; (c) Your income is not enough to pay for basic needs AND court fees.", "es": "Elija una base: (a) recibe beneficios p\u00fablicos; (b) ingreso por debajo de la l\u00ednea de pobreza; (c) ingreso insuficiente.", "zh": "Choose one: (a) You receive public benefits; (b) Your household income is at or below the poverty guidelines; (c) Your income is not enough to pay for basic needs AND court fees.", "vi": "Choose one: (a) You receive public benefits; (b) Your household income is at or below the poverty guidelines; (c) Your income is not enough to pay for basic needs AND court fees.", "so": "Choose one: (a) You receive public benefits; (b) Your household income is at or below the poverty guidelines; (c) Your income is not enough to pay for basic needs AND court fees.", "ti": "Choose one: (a) You receive public benefits; (b) Your household income is at or below the poverty guidelines; (c) Your income is not enough to pay for basic needs AND court fees.", "am": "Choose one: (a) 