INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-fw-003', 'FW-003', 'FW-003', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "FW-003", "form_title": "Order on Court Fee Waiver (Superior Court)", "statutory_authority": "Government Code \u00a7\u00a7 68630-68641", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "court_decision", "fields": [{"field_id": "fw003_decision", "field_label": "Court''s decision on fee waiver", "field_type": "radio", "required": true, "guidance": {"en": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "es": "Este formulario es completado POR EL TRIBUNAL.", "zh": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "vi": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "so": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "ti": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "am": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "ar": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "ht": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "ko": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "pt": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "ru": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing.", "tl": "This form is completed BY THE COURT. The court either: grants the fee waiver (all fees waived), partially grants (some fees waived), or denies. If denied, you have 10 days to request a hearing."}, "legal_reference": "Government Code \u00a7 68634", "common_errors": {}, "tips": {}}, {"field_id": "fw003_denial_reasons", "field_label": "Reasons for denial (if applicable)", "field_type": "textarea", "required": false, "guidance": {"en": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "es": "Si se deniega, el tribunal debe indicar las razones.", "zh": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "vi": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "so": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "ti": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "am": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "ar": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "ht": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "ko": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "pt": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "ru": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days.", "tl": "If denied, the court must state reasons. Common denials: incomplete FW-001, income above threshold, insufficient documentation. You can request a hearing within 10 days."}, "legal_reference": "Government Code \u00a7 68634(e)", "common_errors": {}, "tips": {}}]}]}');
INSERT OR IGNORE INTO court_forms (id, form_code, title, tier, category, field_count, languages, data) VALUES ('form-mc-031', 'MC-031', 'MC-031', 'A', 'California Courts', 0, '["en","es","zh"]', '{"meta": {"form_id": "MC-031", "form_title": "Attached Declaration", "statutory_authority": "CCP \u00a7\u00a7 2009, 2015.5", "languages": ["en", "es", "zh", "vi", "so", "ti", "am", "ar", "ht", "ko", "pt", "ru", "tl"], "version": "1.0.0", "tier": "A", "copyright": "\u00a9 2024-2026 Michael Vernen Thomas Hartmann. All Rights Reserved.", "trademark": "VERNEN\u2122 is a trademark of Michael Vernen Thomas Hartmann."}, "sections": [{"section_id": "declaration_content", "fields": [{"field_id": "mc031_attachment_to", "field_label": "This declaration is attached to (form name/number)", "field_type": "text", "required": true, "guidance": {"en": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "es": "Identifique a cu\u00e1l formulario se adjunta esta declaraci\u00f3n.", "zh": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "vi": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "so": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "ti": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "am": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "ar": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "ht": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "ko": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "pt": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "ru": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies.", "tl": "Identify which form this declaration supports. Example: ''FL-300, Request for Order'' or ''DV-100, Request for DVRO''. This tells the court what motion or request your declaration accompanies."}, "legal_reference": "", "common_errors": {}, "tips": {}}, {"field_id": "mc031_declaration_text", "field_label": "Declaration text", "field_type": "textarea", "required": true, "guidance": {"en": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "es": "Escriba su declaraci\u00f3n jurada de hechos. Numere cada p\u00e1rrafo.", "zh": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "vi": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "so": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "ti": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "am": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "ar": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "ht": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "ko": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "pt": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "ru": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury.", "tl": "Write your sworn statement of facts. Number each paragraph. State only facts within your personal knowledge. Be specific: include dates, times, locations, names, and what you personally witnessed or experienced. Everything you write is under penalty of perjury."}, "legal_reference": "CCP \u00a7 2015.5; Evidence Code \u00a7 702", "common_errors": {"en": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "es": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "zh": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "vi": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "so": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "ti": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "am": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "ar": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "ht": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "ko": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "pt": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "ru": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions.", "tl": "Including hearsay, opinions, or legal arguments. Declarations must contain facts, not conclusions."}, "tips": {"en": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "es": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "zh": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "vi": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "so": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "ti": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "am": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "ar": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "ht": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "ko": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "pt": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "ru": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges.", "tl": "Use chronological order. Start each paragraph with ''On [date], I [observed/did/experienced]...'' This is the most persuasive format for judges."}}]}, {"section_id": "signature", "fields": [{"field_id": "mc031_signature", "field_label": "Signature under penalty of perjury", "field_type": "text", "required": true, "guidance": {"en": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "es": "Firme y feche su declaraci\u00f3n bajo pena de perjurio.", "zh": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "vi": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "so": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "ti": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "am": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "ar": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "ht": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "ko": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "pt": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "ru": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118.", "tl": "Sign and date your declaration. The signature block reads: ''I declare under penalty of perjury under the laws of the State of California that the foregoing is true and correct.'' Making false statements is punishable under Penal Code \u00a7 118."}, "legal_reference": "CCP \u00a7 2015.5; Penal Code \u00a7 118", "common_errors": {}, "tips": {}}]}]}');
